INSERT INTO `ai_playerbot_texts` (`id`, `name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
	(1, 'string_unknown_area', 'the middle of nowhere', 0, 0, '', 'au milieu de nulle part', 'am Arsch der Welt', '荒无人烟之地', '', '', '', 'посреди нигде'),
	(2, 'string_unknown_area', 'an undisclosed location', 0, 0, '', 'un lieu non divulgué', 'an einem geheimen Ort', '某个不为人知的地方', '', '', '', 'в неопределенном месте'),
	(3, 'string_unknown_area', 'somewhere', 0, 0, '', 'Quelque part.', 'irgendwo', '某个地方', '', '', '', 'где-то'),
	(4, 'string_empty_link', 'something', 0, 0, '', 'quelque chose', 'irgendwas', '某样东西', '', '', '', 'что-то'),
	(5, 'broadcast_looting_item_normal', 'wonder what %item_link tastes like', 0, 0, '', 'Je me demande à quoi %item_link peut bien goûter.', 'frag mich, wie %item_link wohl schmeckt', '想知道这%item_link吃起来啥味儿', '', '', '', 'интересно, какой на вкус %item_link'),
	(6, 'broadcast_looting_item_poor', 'nooo, I got %item_link', 0, 0, '', 'Oh non, j’ai reçu %item_link', 'neeein, ich hab %item_link bekommen', '不！我捡了个%item_link', '', '', '', 'нет, мне выпал %item_link'),
	(7, 'broadcast_looting_item_poor', 'aww not this trash again %item_link', 0, 0, '', 'Encore cette poubelle %item_link.', 'ah nee, nicht schon wieder dieser Müll: %item_link', '哎，又是这破烂%item_link', '', '', '', 'опять этот хлам %item_link'),
	(8, 'broadcast_looting_item_poor', 'seem to be looting trash %item_link', 0, 0, '', 'Il semble que je fouille dans les ordures %item_link.', 'scheint so, als würde ich nur Müll looten: %item_link', '看来我捡的都是垃圾%item_link', '', '', '', 'похоже, я лутаю мусор %item_link'),
	(9, 'broadcast_looting_item_poor', 'well, it’s better than nothing I guess %item_link', 0, 0, '', 'Eh bien, c’est toujours mieux que rien, je suppose %item_link', 'naja, besser als nix, schätze ich: %item_link', '好吧，有%item_link总比没有强', '', '', '', ''),
	(10, 'broadcast_looting_item_poor', 'not sure what to do with %item_link', 0, 0, '', 'Je ne suis pas certain de ce qu’il faut faire avec %item_link.', 'keine Ahnung, was ich mit %item_link anfangen soll', '不知道这%item_link能干啥', '', '', '', 'не знаю, что делать с %item_link'),
	(11, 'broadcast_looting_item_normal', 'well, I can keep looting %item_link all day', 0, 0, '', 'Eh bien, je peux passer la journée à looter %item_link!', 'naja, ich kann den ganzen Tag %item_link looten', '好吧，我能捡%item_link捡一天', '', '', '', 'могу лутать %item_link весь день'),
	(12, 'broadcast_looting_item_normal', 'another day, another %item_link', 0, 0, '', 'Encore une journée, encore un %item_link', 'neuer Tag, neuer %item_link', '又是新的一天，又捡了个%item_link', '', '', '', 'еще один день, еще один %item_link'),
	(13, 'broadcast_looting_item_normal', 'looted some %item_link', 0, 0, '', 'J’ai pillé quelques %item_link.', 'hab %item_link gelootet', '捡了点%item_link', '', '', '', 'получил немного %item_link'),
	(14, 'broadcast_looting_item_normal', 'some %item_link is alright', 0, 0, '', 'Certains %item_link passent bien', 'ein %item_link ist okay', '有点%item_link还凑合', '', '', '', 'немного %item_link — это нормально'),
	(15, 'broadcast_looting_item_uncommon', 'not bad, I just got %item_link', 0, 0, '', 'Pas mal du tout, je viens juste de recevoir %item_link', 'nicht schlecht, hab grad %item_link bekommen.', '不错，刚捡到个%item_link', '', '', '', 'неплохо, только что получил %item_link'),
	(16, 'broadcast_looting_item_uncommon', 'just looted %item_link in %zone_name', 0, 0, '', 'Je viens de piller %item_link dans %zone_name.', 'gerade %item_link in %zone_name gelootet', '刚在%zone_name捡到个%item_link', '', '', '', 'только что залутал %item_link в %zone_name'),
	(17, 'broadcast_looting_item_uncommon', 'I could put that to good use %item_link', 0, 0, '', 'Je pourrais bien utiliser ça %item_link', 'kann ich gut gebrauchen, %item_link', '这%item_link我能派上用场', '', '', '', 'могу найти применение %item_link'),
	(18, 'broadcast_looting_item_uncommon', 'money money money %item_link', 0, 0, '', 'L’argent, l’argent, l’argent! %item_link', 'Gold, Gold, Gold: %item_link', '发财了发财了！%item_link', '', '', '', 'деньги, деньги, деньги %item_link'),
	(19, 'broadcast_looting_item_uncommon', 'got %item_link', 0, 0, '', 'J’ai eu %item_link.', 'hab %item_link bekommen', '拿到了%item_link', '', '', '', 'получил %item_link'),
	(20, 'broadcast_looting_item_rare', '%item_link is hunter bis', 0, 0, '', 'Ah, %item_link c’est le meilleur équipement pour les chasseurs.', '%item_link ist BiS für Jäger', '%item_link简直是猎人的极品装备', '', '', '', '%item_link — лучший для охотника'),
	(21, 'broadcast_looting_item_rare', '%item_link is %my_class bis', 0, 0, '', '%item_link est %my_class bis.', '%item_link ist BiS für %my_class', '%item_link对%my_class来说是极品', '', '', '', '%item_link — лучший для %my_class'),
	(22, 'broadcast_looting_item_rare', 'RNG is not bad today %item_link', 0, 0, '', 'La RNG n’est pas mauvaise aujourd’hui %item_link.', 'RNG meint es heute gut: %item_link', '今天人品不错，捡到个%item_link', '', '', '', 'сегодня удача на моей стороне %item_link'),
	(23, 'broadcast_looting_item_rare', 'sweet %item_link, freshly looted', 0, 0, '', 'Doux %item_link, fraîchement looté', 'nice, %item_link frisch gelootet', '太棒了，新鲜出炉的%item_link', '', '', '', 'классный %item_link, только что залутал'),
	(24, 'broadcast_looting_item_rare', 'wow, I just got %item_link', 0, 0, '', 'wow, je viens de recevoir %item_link', 'wow, hab gerade %item_link bekommen', '哇，我刚捡到个%item_link', '', '', '', 'вау, только что получил %item_link'),
	(25, 'broadcast_looting_item_rare', '%item_link is hunter bis', 0, 0, '', 'Ah, %item_link, c’est le meilleur équipement pour les chasseurs.', '%item_link ist BiS für Jäger', '%item_link是猎人的顶级装备', '', '', '', '%item_link — лучший для охотника'),
	(26, 'broadcast_looting_item_rare', '%item_link is %my_class bis', 0, 0, '', '%item_link est %my_class bis.', '%item_link ist BiS für %my_class', '%item_link对%my_class来说是顶级货', '', '', '', '%item_link — лучший для %my_class'),
	(27, 'broadcast_looting_item_rare', 'RNG is not bad today %item_link', 0, 0, '', 'Aujourd’hui, la RNG n’est pas mauvaise %item_link.', 'RNG meint es heute gut: %item_link', '今天运气真好，捡到%item_link', '', '', '', 'сегодня удача на моей стороне %item_link'),
	(28, 'broadcast_looting_item_rare', 'sweet %item_link, freshly looted', 0, 0, '', 'Oh, %item_link, fraîchement pillé', 'nice, %item_link frisch gelootet', '太好了，刚捡到个%item_link', '', '', '', 'классный %item_link, только что залутал'),
	(29, 'broadcast_looting_item_epic', 'OMG, look at what I just got %item_link!!!', 0, 0, '', 'OMG, regardez ce que je viens d’obtenir %item_link !!!', 'OMG, guckt mal, was ich gerade bekommen hab: %item_link!!!', '天啊，快看我刚捡到的%item_link！！！', '', '', '', 'ОГО, посмотрите, что я только что получил %item_link!!!'),
	(30, 'broadcast_looting_item_legendary', 'No @#$@% way! This can not be, I got %item_link, this is insane', 0, 0, '', 'Pas moyen! Ça ne peut pas être vrai, j’ai obtenu %item_link, c’est fou!', 'Keine @#$@% Chance! Ich hab %item_link bekommen, Wahnsinn.', '不是吧！这不可能，我竟然捡到%item_link，太疯狂了！', '', '', '', 'Нет @#$@%! Не может быть, я получил %item_link, это безумие'),
	(31, 'broadcast_looting_item_artifact', 'No @#$@% way! This can not be, I got %item_link, this is insane', 0, 0, '', 'Pas possible! Ça ne peut pas être vrai, j’ai eu %item_link, c’est fou', 'Keine @#$@% Chance! Das kann nicht sein - ich hab %item_link bekommen, völlig irre.', '天哪！这不可能，我拿到了%item_link，简直不敢相信！', '', '', '', 'Нет @#$@%! Не может быть, я получил %item_link, это безумие'),
	(32, 'broadcast_looting_item_poor', 'Seriously? Another %item_link? My luck is broken.', 0, 0, '', 'Sérieusement? Encore un %item_link? La poisse me suit, c’est pas possible.', 'Im Ernst? Noch ein %item_link? Mein Glück ist kaputt.', '不是吧？又是个%item_link？我的运气真是烂透了。', '', '', '', ''),
	(33, 'broadcast_looting_item_poor', 'This %item_link is not even worth the pixels it’s printed on.', 0, 0, '', 'Cet %item_link ne vaut même pas les pixels sur lesquels il est imprimé.', 'Dieser %item_link ist nicht mal die Pixel wert, auf denen er angezeigt wird.', '这%item_link连显示它的像素都不值。', '', '', '', ''),
	(34, 'broadcast_looting_item_poor', 'I got %item_link... Ugh, here we go again.', 0, 0, '', 'J’ai de nouveau %item_link... Oh là là, c’est reparti.', 'Ich hab %item_link... ugh, schon wieder.', '我又捡到个%item_link...哎，又来了。', '', '', '', ''),
	(35, 'broadcast_looting_item_poor', 'I don’t even know why I’m picking up %item_link, it’s useless.', 0, 0, '', 'Je me demande pourquoi je prends %item_link, c’est inutile.', 'Keine Ahnung, warum ich %item_link überhaupt aufhebe, es ist nutzlos.', '我都不知道为啥要捡%item_link，完全没用。', '', '', '', ''),
	(36, 'broadcast_looting_item_poor', 'Look at this shiny %item_link... too bad it’s garbage.', 0, 0, '', 'Regarde ce magnifique %item_link... dommage que ce soit de la camelote.', 'Schaut euch diesen glänzenden %item_link an... schade, ist trotzdem Müll.', '看看这闪亮的%item_link...可惜就是个垃圾。', '', '', '', ''),
	(37, 'broadcast_looting_item_poor', 'This %item_link isn’t even worth the paper it’s written on.', 0, 0, '', '%item_link ne vaut même pas le papier sur lequel il est écrit.', 'Dieser %item_link ist nicht mal das Papier wert, auf dem er stehen würde.', '这%item_link连写它的羊皮纸都不值。', '', '', '', ''),
	(38, 'broadcast_looting_item_poor', 'I guess %item_link is better than nothing? Barely.', 0, 0, '', 'Je suppose que %item_link vaut mieux que rien ? À peine.', 'Ich schätze, %item_link ist besser als gar nix? Gerade so.', '我想%item_link总比没有强吧？勉强。', '', '', '', ''),
	(39, 'broadcast_looting_item_poor', 'Not sure what to do with %item_link, maybe I’ll just sell it for 1 silver.', 0, 0, '', 'Je ne suis pas sûr de ce que faire avec %item_link, peut-être que je vais juste le vendre pour 1 pièce d’argent.', 'Kein Plan, was ich mit %item_link machen soll, vielleicht verkauf ich es für 1 Silber.', '不知道%item_link能干嘛，或许卖1个银币得了。', '', '', '', ''),
	(40, 'broadcast_looting_item_poor', 'Another %item_link... well, at least I’m getting something.', 0, 0, '', 'Encore un %item_link... eh bien, au moins je reçois quelque chose.', 'Noch ein %item_link... naja, immerhin krieg ich was.', '又是个%item_link...好吧，至少有点收获。', '', '', '', ''),
	(41, 'broadcast_looting_item_poor', 'I hope %item_link is actually worth something because it looks awful.', 0, 0, '', 'J’espère que %item_link vaut en fait quelque chose parce que ça a l’air affreux.', 'Hoffentlich ist %item_link was wert, es sieht nämlich furchtbar aus.', '希望%item_link能值点钱，因为它看起来真垃圾。', '', '', '', ''),
	(42, 'broadcast_looting_item_poor', 'Is %item_link a joke? Someone’s laughing at me.', 0, 0, '', '%item_link c’est une blague ? Quelqu’un se moque de moi.', 'Ist %item_link ein Witz? Irgendwer lacht mich aus.', '这%item_link是开玩笑吗？谁在嘲笑我啊！', '', '', '', ''),
	(43, 'broadcast_looting_item_poor', 'Why do I keep getting %item_link... did I anger RNG?', 0, 0, '', 'Pourquoi est-ce que je continue à obtenir %item_link... est-ce que j’ai fâché le RNG?', 'Warum krieg ich ständig %item_link... hab ich RNG verärgert?', '为啥我老是拿到%item_link……我是不是得罪了随机之神？', '', '', '', ''),
	(44, 'broadcast_looting_item_poor', 'It’s like %item_link is following me around. I don’t want it!', 0, 0, '', 'C’est comme si %item_link me suivait partout. Je ne veux pas de ça !', 'Als würde %item_link mir nachlaufen. Ich will das nicht!', '这%item_link就像缠着我一样，我才不要呢！', '', '', '', ''),
	(45, 'broadcast_looting_item_poor', 'There’s %item_link, again. What a surprise.', 0, 0, '', 'Encore %item_link. Quelle surprise.', 'Da ist %item_link schon wieder. Was für eine Überraschung.', '又是%item_link，真是“惊喜”啊。', '', '', '', ''),
	(46, 'broadcast_looting_item_poor', 'I guess %item_link is good for vendor trash?', 0, 0, '', 'I présume qu’ %item_link est bon pour vendre à un marchand ?', 'Ich schätze, %item_link taugt als Händler-Müll?', '看来%item_link只能当垃圾卖给商人了？', '', '', '', ''),
	(47, 'broadcast_looting_item_poor', 'Noooo, not %item_link again! RNG, please!', 0, 0, '', 'Oh non, pas encore %item_link! RNG s’il te plaît!', 'Neeeein, nicht schon wieder %item_link! RNG, bitte!', '不！别又是%item_link！随机之神，求放过！', '', '', '', ''),
	(48, 'broadcast_looting_item_poor', 'Well, at least %item_link isn’t completely useless, right?', 0, 0, '', 'Eh bien, au moins %item_link n’est pas complètement inutile, n’est-ce pas?', 'Naja, ganz nutzlos ist %item_link immerhin nicht, oder?', '好吧，至少%item_link还不算完全没用，对吧？', '', '', '', ''),
	(49, 'broadcast_looting_item_poor', 'Another %item_link? RNG, do you even care?', 0, 0, '', 'Encore %item_link ? La RNG est-ce que ça te dit quelque chose au moins?', 'Noch ein %item_link? RNG, kümmert dich das überhaupt?', '又一个%item_link？随机之神，你在乎过我的感受吗？', '', '', '', ''),
	(50, 'broadcast_looting_item_poor', 'Maybe %item_link will be worth something in 10 years.', 0, 0, '', 'Peut-être que %item_link vaudra quelque chose dans 10 ans.', 'Vielleicht ist %item_link in 10 Jahren was wert.', '或许%item_link十年后能值点钱吧。', '', '', '', ''),
	(51, 'broadcast_looting_item_poor', 'I guess I’ll just admire how %item_link looks... and throw it away.', 0, 0, '', 'Je suppose que je vais juste admirer %item_link ... et le jeter.', 'Ich bewundere einfach mal, wie %item_link aussieht... und schmeiß es weg.', '我就欣赏一下%item_link的样子……然后扔了吧。', '', '', '', ''),
	(52, 'broadcast_looting_item_poor', 'Who needs %item_link? Not me, that’s for sure.', 0, 0, '', 'Qui a besoin de %item_link ? Pas moi en tout cas, ça c’est sûr.', 'Wer braucht %item_link? Ich sicher nicht.', '谁需要%item_link啊？反正我肯定不要。', '', '', '', ''),
	(53, 'broadcast_looting_item_poor', 'Maybe %item_link will be useful... just kidding, it’s trash.', 0, 0, '', 'Peut-être que %item_link sera utile... non, je plaisante, c’est nul.', 'Vielleicht ist %item_link nützlich... haha, doch nur Müll.', '也许%item_link有用……开玩笑的，就是个垃圾。', '', '', '', ''),
	(54, 'broadcast_looting_item_poor', 'The universe has given me %item_link. Great.', 0, 0, '', 'L’univers m’a donné %item_link. Génial.', 'Das Universum schenkt mir %item_link. Toll.', '宇宙赐予了我%item_link，棒极了。', '', '', '', ''),
	(55, 'broadcast_looting_item_poor', 'Well, I have %item_link. Can’t say I’m thrilled.', 0, 0, '', 'Eh bien, j’ai %item_link. Franchement, je ne suis pas super emballé.', 'Gut, ich hab %item_link. Begeistert bin ich nicht.', '好吧，我拿到了%item_link，可一点也高兴不起来。', '', '', '', ''),
	(56, 'broadcast_looting_item_poor', 'What am I even going to do with %item_link? Can’t even sell it.', 0, 0, '', 'Qu’est-ce que je vais bien pouvoir faire avec %item_link ? Je ne peux même pas le vendre.', 'Was soll ich überhaupt mit %item_link anfangen? Nicht mal verkaufbar.', '我拿%item_link能干啥？连卖都卖不掉。', '', '', '', ''),
	(57, 'broadcast_looting_item_poor', 'Let’s add %item_link to my growing pile of disappointment.', 0, 0, '', 'Ajoutons %item_link à ma pile croissante de déceptions.', 'Packen wir %item_link zu meinem wachsenden Enttäuschungsstapel.', '把%item_link扔进我那堆失望的垃圾里吧。', '', '', '', ''),
	(58, 'broadcast_looting_item_poor', 'Thanks for %item_link... it’s exactly what I didn’t need.', 0, 0, '', 'Merci pour %item_link... c’est exactement ce qu’il me fallait pas.', 'Danke für %item_link... genau das, was ich nicht gebraucht hab.', '谢谢给了我%item_link……这正是我不需要的东西。', '', '', '', ''),
	(59, 'broadcast_looting_item_poor', 'Another %item_link... RNG, we need to talk.', 0, 0, '', 'Encore un %item_link... RNG, on doit avoir une discussion.', 'Noch ein %item_link... RNG, wir müssen reden.', '又一个%item_link……随机之神，咱们得谈谈。', '', '', '', ''),
	(60, 'broadcast_looting_item_poor', 'I’ve looted so many %item_link, I could open a store with them.', 0, 0, '', 'J’ai récupéré tellement de %item_link, je pourrais ouvrir un magasin avec.', 'Ich hab so viele %item_link gelootet, ich könnte damit einen Laden aufmachen.', '我捡了这么多%item_link，够开个杂货铺了。', '', '', '', ''),
	(61, 'broadcast_looting_item_poor', 'A shiny %item_link... maybe for the trash pile.', 0, 0, '', 'Un brillant %item_link... peut-être destiné à la poubelle.', 'Ein glänzender %item_link... kommt wohl auf den Müllhaufen.', '一个闪亮的%item_link……大概只能扔垃圾堆了。', '', '', '', ''),
	(62, 'broadcast_looting_item_poor', 'It’s %item_link, everybody. Don’t get too excited.', 0, 0, '', 'C’est %item_link, tout le monde. Pas de quoi s’affoler.', 'Es ist %item_link, Leute. Nicht zu früh freuen.', '各位，这是%item_link，别太激动哦。', '', '', '', ''),
	(63, 'broadcast_looting_item_poor', 'Well, at least it’s %item_link... could be worse.', 0, 0, '', 'Eh bien, au moins c’est %item_link... ça pourrait être pire.', 'Naja, wenigstens ist es %item_link... könnte schlimmer sein.', '好吧，至少是%item_link……还能更糟呢。', '', '', '', ''),
	(64, 'broadcast_looting_item_poor', 'I’ll take %item_link over nothing.', 0, 0, '', 'Je préfère %item_link à rien du tout.', 'Lieber %item_link als gar nix.', '有%item_link总比啥也没有强。', '', '', '', ''),
	(65, 'broadcast_looting_item_poor', 'Another %item_link. Not the worst.', 0, 0, '', 'Encore un %item_link. Pas le pire.', 'Noch ein %item_link. Nicht das Schlimmste.', '又一个%item_link，还不算最差。', '', '', '', ''),
	(66, 'broadcast_looting_item_poor', 'Hey, %item_link... it’s okay, I suppose.', 0, 0, '', 'Salut, %item_link... c’est correct, je suppose.', 'Hey, %item_link... ist schon okay, denk ich.', '嘿，%item_link……还行吧，我觉得。', '', '', '', ''),
	(67, 'broadcast_looting_item_normal', 'Hey, %item_link. Not bad, not great, but I’ll take it.', 0, 0, '', 'Salut, %item_link. Pas mal, pas super, mais je vais le prendre.', 'Hey, %item_link. Nicht schlecht, nicht gut, aber ich nehme es.', '嘿，%item_link。不算好也不算差，拿了再说。', '', '', '', ''),
	(68, 'broadcast_looting_item_normal', 'Could be worse... I just looted %item_link.', 0, 0, '', 'Ça aurait pu être pire... Je viens juste de mettre la main sur %item_link.', 'Könnte schlimmer sein... hab gerade %item_link gelootet.', '还行吧……刚捡到个%item_link。', '', '', '', ''),
	(69, 'broadcast_looting_item_normal', 'I guess %item_link will come in handy for something.', 0, 0, '', 'Je suppose que %item_link va être utile pour quelque chose.', '%item_link wird für irgendwas nützlich sein, denke ich.', '我觉得%item_link总能派上点用场。', '', '', '', ''),
	(70, 'broadcast_looting_item_normal', 'Another day, another %item_link. Can’t complain.', 0, 0, '', 'Encore une journée, encore un %item_link. Je ne vais pas me plaindre.', 'Neuer Tag, neuer %item_link. Kann mich nicht beschweren.', '又是新的一天，又捡到个%item_link，挺好。', '', '', '', ''),
	(71, 'broadcast_looting_item_normal', 'Well, %item_link is alright, I guess.', 0, 0, '', 'Hmm, %item_link, c’est pas mal, je suppose.', 'Naja, %item_link geht klar, würd ich sagen.', '嗯，%item_link还行吧，我觉得。', '', '', '', ''),
	(72, 'broadcast_looting_item_normal', 'Just got %item_link. It’s not the best, but it’s something.', 0, 0, '', 'Je viens de récupérer %item_link. Ce n’est pas le meilleur, mais c’est mieux que rien.', 'Gerade %item_link bekommen. Nicht das Beste, aber etwas.', '刚拿到%item_link，不是最好的，但也算有点收获。', '', '', '', ''),
	(73, 'broadcast_looting_item_normal', 'Could be worse, at least it’s %item_link.', 0, 0, '', 'Ça pourrait être pire, au moins c’est %item_link.', 'Könnte schlimmer sein, immerhin ist es %item_link.', '还能更糟呢，至少是%item_link。', '', '', '', ''),
	(74, 'broadcast_looting_item_normal', '%item_link is good enough, I’m not mad.', 0, 0, '', '%item_link est assez bon, je ne suis pas fâché.', '%item_link ist gut genug, ich bin nicht sauer.', '%item_link还不错，我没啥好抱怨的。', '', '', '', ''),
	(75, 'broadcast_looting_item_normal', 'It’s no legendary, but %item_link will do.', 0, 0, '', 'Ce n’est pas légendaire, mais %item_link fera l’affaire.', 'Kein Legendary, aber %item_link reicht.', '虽然不是传说装备，但%item_link也凑合了。', '', '', '', ''),
