	(348, 'broadcast_levelup_max_level', 'Just hit %my_level, get ready for the real challenges!', 0, 0, '', 'Je viens d’atteindre mon niveau %my_level, je suis prêt pour affronter de vrais défis !', 'Gerade Level %my_level erreicht, macht euch bereit für echte Herausforderungen!', '刚到%my_level级，准备好迎接真正的挑战吧！', '', '', '', ''),
	(349, 'broadcast_levelup_max_level', 'Level %my_level complete, it’s time for the epic content!', 0, 0, '', 'Niveau %my_level complet, il est temps pour le contenu épique !', 'Level %my_level voll, Zeit für epischen Content!', '%my_level级达成，是时候体验史诗内容了！', '', '', '', ''),
	(350, 'broadcast_levelup_max_level', 'Fresh out of %my_level! Ready for endgame dungeons!', 0, 0, '', 'Je viens enfin d’atteindre %my_level ! Prêt pour les donjons de fin de jeu !', 'Frisch auf Level %my_level! Bereit für Endgame-Inis!', '刚到%my_level级！准备好挑战终极地下城了！', '', '', '', ''),
	(351, 'broadcast_levelup_max_level', 'Now that I’m level %my_level, nothing is beyond my reach!', 0, 0, '', 'Maintenant que je suis au niveau %my_level, rien ne peut m’arrêter !', 'Jetzt, wo ich Level %my_level bin, ist nichts mehr außerhalb meiner Reichweite!', '现在我是%my_level级，没有什么是我做不到的！', '', '', '', ''),
	(352, 'broadcast_levelup_max_level', 'It’s official! Level %my_level, time to dominate!', 0, 0, '', 'C’est officiel ! Niveau %my_level, c’est le moment de tout déchirer !', 'Jetzt ist es offiziell! Level %my_level, Zeit zu dominieren!', '正式宣布！%my_level级，是时候称霸一方了！', '', '', '', ''),
	(353, 'broadcast_levelup_max_level', 'Made it to level %my_level! Time to make my mark on the world!', 0, 0, '', 'J’ai atteint le niveau %my_level! Le moment de laisser ma trace dans le monde est enfin arrivé!', 'Level %my_level geschafft! Zeit, der Welt meinen Stempel aufzudrücken!', '达到%my_level级了！是时候在这个世界上留下我的印记了！', '', '', '', ''),
	(354, 'broadcast_levelup_max_level', 'Level %my_level unlocked! The real fun begins now!', 0, 0, '', 'Niveau %my_level débloqué! Maintenant, les choses sérieuses commencent!', 'Level %my_level freigeschaltet! Jetzt beginnt der echte Spaß!', '%my_level级解锁！真正的乐趣现在才开始！', '', '', '', ''),
	(355, 'broadcast_levelup_max_level', 'Level %my_level, and the world is my playground!', 0, 0, '', 'Niveau %my_level, et le monde est mon terrain de jeu!', 'Level %my_level, und die Welt ist mein Spielplatz!', '%my_level级，这个世界就是我的游乐场！', '', '', '', ''),
	(356, 'broadcast_levelup_max_level', 'Level %my_level, ready to show the world my power!', 0, 0, '', 'Niveau %my_level, prêt à montrer au monde ma puissance !', 'Level %my_level, bereit, der Welt meine Power zu zeigen!', '%my_level级，准备好向世界展示我的力量了！', '', '', '', ''),
	(357, 'broadcast_levelup_max_level', 'Just hit %my_level, I’m going all in now!', 0, 0, '', 'Je viens d’atteindre %my_level, je me lance à fond maintenant !', 'Gerade %my_level erreicht, jetzt geh ich all in!', '刚到%my_level级，现在我要全力以赴了！', '', '', '', ''),
	(358, 'broadcast_levelup_max_level', 'Level %my_level, I can finally take on everything!', 0, 0, '', 'Niveau %my_level, je peux enfin tout affronter !', 'Level %my_level, endlich kann ich alles angehen!', '%my_level级，我终于能挑战一切了！', '', '', '', ''),
	(359, 'broadcast_levelup_max_level', 'Level %my_level, I’m feeling unstoppable!', 0, 0, '', 'Niveau %my_level, je me sens imbattable!', 'Level %my_level, fühl mich unaufhaltbar!', '%my_level级，我感觉自己势不可挡！', '', '', '', ''),
	(360, 'broadcast_levelup_max_level', 'Just reached level %my_level, can’t wait to dive into the endgame!', 0, 0, '', 'Je viens d’atteindre le niveau %my_level, j’ai hâte de me plonger dans le contenu de fin de jeu!', 'Gerade Level %my_level erreicht, kanns kaum erwarten ins Endgame zu springen!', '刚达到%my_level级，迫不及待要投入终极内容了！', '', '', '', ''),
	(361, 'broadcast_guild_promotion', 'Good job %other_name. You deserved this.', 0, 0, '', 'Bien joué %other_name. Tu l’as bien mérité.', 'Gute Arbeit, %other_name. Das hast du dir verdient.', '干得好，%other_name，你当之无愧！', '', '', '', 'Молодец %other_name. Ты это заслужил.'),
	(362, 'broadcast_guild_demotion', 'That was awful %other_name. I hate to do this but...', 0, 0, '', 'Désolé %other_name, mais ça a été horrible. Je déteste devoir faire ça, mais...', 'Das war mies, %other_name. Ich mags nicht, aber...', '太糟糕了，%other_name，我也不想这么做，但是...', '', '', '', 'Это было ужасно %other_name. Не хотел этого делать, но...'),
	(363, 'broadcast_guild_promotion', 'Congrats %other_name, you’ve earned this promotion!', 0, 0, '', 'Félicitations %other_name, tu as mérité cette promotion !', 'Glückwunsch, %other_name, du hast den Aufstieg verdient!', '恭喜你，%other_name，这晋升是你应得的！', '', '', '', ''),
	(364, 'broadcast_guild_promotion', 'Well deserved %other_name, welcome to the next level!', 0, 0, '', 'Bien mérité %other_name, bienvenue au niveau suivant !', 'Verdient, %other_name - willkommen im nächsten Level!', '名副其实，%other_name，欢迎进入下一阶段！', '', '', '', ''),
	(365, 'broadcast_guild_promotion', '%other_name is leveling up! Congratulations on the promotion!', 0, 0, '', '%other_name progresse dans sa carrière ! Félicitations pour la promotion !', '%other_name steigt auf! Glückwunsch zur Beförderung!', '%other_name升职了！恭喜晋升！', '', '', '', ''),
	(366, 'broadcast_guild_promotion', 'Promotion time! %other_name, you’ve earned this one!', 0, 0, '', 'Promotion time! %other_name, tu l’as bien mérité !', 'Beförderungszeit! %other_name, die hast du dir verdient!', '晋升时刻！%other_name，你当之无愧！', '', '', '', ''),
	(367, 'broadcast_guild_promotion', 'A new role for %other_name! Well done, keep it up!', 0, 0, '', 'Une nouvelle fonction pour %other_name ! Bravo, continue comme ça !', 'Neue Rolle für %other_name! Gut gemacht, weiter so!', '%other_name获得了新角色！干得漂亮，继续加油！', '', '', '', ''),
	(368, 'broadcast_guild_promotion', 'Huge congrats to %other_name, you’ve earned a well-deserved promotion!', 0, 0, '', '%other_name, félicitations pour ta super promotion, tu la mérites amplement!', 'Dickes Gratz an %other_name, wohlverdiente Beförderung!', '热烈祝贺%other_name，你实至名归地获得了晋升！', '', '', '', ''),
	(369, 'broadcast_guild_promotion', 'Let’s all give a round of applause to %other_name, for the promotion!', 0, 0, '', 'Donnons tous un grand round d’applaudissements à %other_name pour sa promotion!', 'Applaus für %other_name zur Beförderung!', '让我们为%other_name的晋升鼓掌庆祝吧！', '', '', '', ''),
	(370, 'broadcast_guild_promotion', 'Cheers to %other_name on the promotion! Keep shining!', 0, 0, '', 'Salut à %other_name pour sa promotion! Continue de briller!', 'Gratulation an %other_name zur Beförderung! Weiter so!', '为%other_name的晋升干杯！继续发光发热！', '', '', '', ''),
	(371, 'broadcast_guild_promotion', 'Congrats %other_name, you’re moving up! Well done!', 0, 0, '', 'Félicitations %other_name, tu progresses dans ton parcours ! Bravo !', 'Gratz, %other_name, du steigst auf! Gut gemacht!', '恭喜%other_name，你更进一步了！干得好！', '', '', '', ''),
	(372, 'broadcast_guild_promotion', 'Another step up for %other_name! Congratulations!', 0, 0, '', 'Encore une promotion pour %other_name ! Félicitations !', 'Noch ein Schritt nach oben für %other_name! Glückwunsch!', '%other_name又迈上新台阶！恭喜！', '', '', '', ''),
	(373, 'broadcast_guild_demotion', 'Tough decision, but %other_name, you’ve been demoted. Time to step up!', 0, 0, '', 'Décision difficile, mais %other_name, tu as été rétrogradé. C’est le moment de te ressaisir!', 'Harte Entscheidung, aber %other_name, du wurdest degradiert. Zeit, dich zu beweisen!', '艰难的决定，%other_name，你被降职了。加把劲吧！', '', '', '', ''),
	(374, 'broadcast_guild_demotion', 'Sorry %other_name, but it’s time for a demotion. Hope you come back stronger!', 0, 0, '', 'Désolé %other_name, mais c’est l’heure d’une rétrogradation. J’espère que tu reviendras plus fort !', 'Sorry, %other_name, aber es gibt eine Degradierung. Komm stärker zurück!', '抱歉，%other_name，现在得降职了。希望你能更强地回来！', '', '', '', ''),
	(375, 'broadcast_guild_demotion', 'Unfortunately, %other_name, it’s a demotion this time. You’ll get \'em next time!', 0, 0, '', '', 'Leider, %other_name, diesmal eine Degradierung. Beim nächsten Mal packst du es!', '遗憾的是，%other_name，这次是降职。下次再努力吧！', '', '', '', ''),
	(376, 'broadcast_guild_demotion', 'A hard decision, but %other_name, you’ve been demoted. Time to grind back up!', 0, 0, '', 'Une décision difficile, mais %other_name, tu as été rétrogradé. Il est temps de remonter la pente !', 'Schwere Entscheidung, aber %other_name, du wurdest degradiert. Zeit, dich wieder hochzugrinden!', '艰难的决定，%other_name，你被降职了。是时候努力爬回去了！', '', '', '', ''),
	(377, 'broadcast_guild_demotion', 'We hate to see it, but %other_name, it’s a demotion for now.', 0, 0, '', 'C’est toujours difficile à accepter, %other_name, mais pour le moment, c’est une rétrogradation.', 'Unschön, aber %other_name, vorerst eine Degradierung.', '我们也不想看到，%other_name，但现在是降职。', '', '', '', ''),
	(378, 'broadcast_guild_demotion', 'Sorry %other_name, your rank has been lowered. Let’s work harder together!', 0, 0, '', 'Désolé %other_name, ton rang a été abaissé. On va devoir redoubler d’efforts ensemble !', 'Sorry, %other_name, dein Rang wurde gesenkt. Lass uns zusammen härter arbeiten!', '对不起，%other_name，你的等级被降低了。咱们一起更努力吧！', '', '', '', ''),
	(379, 'broadcast_guild_demotion', 'A demotion for %other_name... Time to focus and rise back up!', 0, 0, '', 'Une rétrogradation pour %other_name... Il est temps de se concentrer et de remonter la pente!', 'Eine Degradierung für %other_name... Zeit, sich zu fokussieren und wieder hochzukommen!', '%other_name被降职了...是时候集中精力再爬上去了！', '', '', '', ''),
	(380, 'broadcast_guild_demotion', 'Not what we wanted, but %other_name, you’ve been demoted. Learn and come back stronger!', 0, 0, '', 'Pas ce que nous voulions, mais %other_name, tu as été rétrogradé. Apprends et reviens plus fort !', 'Nicht das, was wir wollten, aber %other_name, du wurdest degradiert. Lern draus und komm stärker zurück!', '这不是我们想要的，%other_name，你被降职了。吸取教训，变得更强吧！', '', '', '', ''),
	(381, 'broadcast_guild_demotion', 'A tough moment for %other_name, but we know you can bounce back from this demotion!', 0, 0, '', 'Un moment difficile pour %other_name, mais on sait que tu peux rebondir après cette rétrogradation!', 'Harter Moment für %other_name, aber wir wissen, du kommst von der Degradierung zurück!', '对%other_name来说是艰难的一刻，但我们相信你能从这次降职中恢复！', '', '', '', ''),
	(382, 'broadcast_guild_demotion', 'Sorry %other_name, but a demotion has been applied. It’s time for improvement!', 0, 0, '', 'Désolé %other_name, mais une rétrogradation a été appliquée. Il est temps de s’améliorer !', 'Sorry, %other_name, aber du wurdest degradiert. Zeit für Verbesserungen!', '抱歉，%other_name，你被降职了。是时候改进自己了！', '', '', '', ''),
	(383, 'broadcast_guild_demotion', 'We didn’t want this for %other_name, but a demotion has occurred. Time to get better!', 0, 0, '', 'On n’a pas voulu cela pour %other_name, mais une rétrogradation a eu lieu. Il est temps de s’améliorer !', 'Wir wollten das nicht für %other_name, aber es gab eine Degradierung. Zeit, besser zu werden!', '我们不希望这样，%other_name，但降职已发生。是时候变得更好了！', '', '', '', ''),
	(384, 'broadcast_guild_recruitment', 'Looking for fresh blood! Join the guild, be part of something great!', 0, 0, '', 'À la recherche de sang neuf ! Rejoins la guilde, fais partie de quelque chose de grandiose !', 'Frisches Blut gesucht! Tritt der Gilde bei, sei Teil von was Großem!', '寻找新鲜血液！加入我们的公会，一起成就伟业！', '', '', '', ''),
