	(869, 'suggest_something', 'Who else thinks %zone_name is trying to kill us?', 0, 0, '', 'Qui d’autre pense que %zone_name essaie de nous tuer ?', 'Noch wer, der denkt das %zone_name uns umbringen will?', '还有谁觉得%zone_name是想弄死咱们？', '', '¿Quién más cree que %zone_name está tratando de matarnos?', '', 'Кто еще думает, что %zone_name пытается нас убить?'),
	(870, 'suggest_something', 'I’m on a wild ride through %zone_name!', 0, 0, '', 'Je suis en train de vivre une aventure folle à travers %zone_name !', 'Ich bin auf wilder Fahrt durch %zone_name!', '我在%zone_name经历了一场狂野冒险！', '', '¡Estoy en una aventura salvaje a través de %zone_name!', '', 'Я на дикой поездке через %zone_name!'),
	(871, 'suggest_something', 'Is it just me or is %zone_name getting weirder?', 0, 0, '', 'Est-ce que c’est moi ou %zone_name devient de plus en plus étrange ?', 'Bin das nur ich, oder wird %zone_name immer weirder?', '是我一个人觉得%zone_name越来越诡异了吗？', '', '¿Soy solo yo o %zone_name se está volviendo más raro?', '', 'Только мне кажется, что %zone_name становится все страннее?'),
	(872, 'suggest_something', 'I’m convinced %zone_name is secretly an amusement park.', 0, 0, '', 'Je suis convaincu que %zone_name est secrètement un parc d’attractions.', 'Ich bin davon überzeugt, das %zone_name heimlich ein Freizeitpark ist.', '我敢肯定%zone_name其实是个隐秘的游乐园！', '', 'Estoy convencido de que %zone_name es secretamente un parque de atracciones.', '', 'Я убежден, что %zone_name — это тайный парк аттракционов.'),
	(873, 'suggest_something_toxic', 'why is my keyboard not working, is it because I don’t have enough friends', 0, 0, '', 'Pourquoi mon clavier ne fonctionne pas ? Ce doit être parceque je n’ai pas d’amis ....', 'Tastatur kaputt... wahrscheinlich wieder zu wenig Freunde.', '我的键盘怎么不好使了，是因为我朋友不够多吗？', '', '', '', ''),
