	(996, 'thunderfury_spam', 'Can someone get me a %thunderfury_link? Asking for a friend... maybe even two!', 0, 0, '', 'Est-ce que quelqu’un peut me trouver un %thunderfury_link ? Je demande pour un ami... peut-être même deux !', 'kann mir jemand ne %thunderfury_link besorgen? frage für einen Freund... vielleicht zwei!', '谁能帮我搞把%thunderfury_link？替朋友问的……可能还得两把！', '', '', '', ''),
	(997, 'thunderfury_spam', 'Hey, did %thunderfury_link just *smite* something? I swear I felt the ground shake.', 0, 0, '', 'Hey, est-ce que %thunderfury_link vient de *foudroyer* quelque chose ? Je te jure que j’ai senti la terre trembler.', 'hat %thunderfury_link da gerade was *gesmitet*? ich schwöre, der Boden hat gewackelt', '嘿，%thunderfury_link刚是不是劈了什么？我发誓感觉地面都在抖！', '', '', '', ''),
