	(1000, 'thunderfury_spam', 'Wait, did I just see someone wielding %thunderfury_link?!', 0, 0, '', 'Attends, est-ce que je viens de voir quelqu’un manier %thunderfury_link ?!', 'hab ich gerade jemanden mit %thunderfury_link gesehen?!', '等等，我刚是不是看到有人拿着%thunderfury_link？！', '', '', '', ''),
	(1001, 'thunderfury_spam', 'The power of %thunderfury_link is *undeniable*', 0, 0, '', 'Le pouvoir de %thunderfury_link est *indéniable*', 'Die Macht von %thunderfury_link ist *unbestreitbar*', '%thunderfury_link的力量*无可否认*！', '', '', '', ''),
	(1002, 'thunderfury_spam', 'I’m 99% sure that was %thunderfury_link. 1% might have been a random NPC, tho.', 0, 0, '', 'Je suis à 99% certain que c’était %thunderfury_link. Le 1% restant aurait pu être un PNJ aléatoire, cependant.', 'Bin zu 99% sicher, das war %thunderfury_link. Zu 1% wars vielleicht nur ein random NPC.', '我99%确定那是%thunderfury_link。不过1%可能是随机NPC吧。', '', '', '', ''),
	(1003, 'thunderfury_spam', '%thunderfury_link in action! Who needs an army when you’ve got that kind of power?', 0, 0, '', '%thunderfury_link en action ! Qui a besoin d’une armée lorsqu’on a ce genre de puissance ?', '%thunderfury_link in Aktion! Wer braucht ne Armee, mit so einer Power?', '%thunderfury_link出手了！有这种力量谁还需要军队？', '', '', '', ''),
	(1004, 'thunderfury_spam', 'I heard %thunderfury_link is what really brings all the boys to the yard.', 0, 0, '', 'J’ai entendu dire que %thunderfury_link, c’est ce qui attire vraiment tous les garçons dans la cour.', 'Hab gehört, %thunderfury_link lockt alle Jungs an.', '听说%thunderfury_link才是真正吸引大家的东西！', '', '', '', ''),
	(1005, 'thunderfury_spam', 'Why even use %thunderfury_link when %thunderfury_link is clearly the superior option?', 0, 0, '', 'Pourquoi même utiliser %thunderfury_link quand %thunderfury_link est clairement l’option supérieure ?', 'Warum überhaupt %thunderfury_link nutzen, wenn %thunderfury_link klar die bessere Option ist?', '干嘛还用%thunderfury_link，%thunderfury_link明显是更好的选择啊！', '', '', '', ''),
