	(1007, 'thunderfury_spam', 'I thought I heard %thunderfury_link, but it was just the sound of sheer awesome.', 0, 0, '', 'J’ai cru entendre %thunderfury_link, mais en fait c’était juste le son de la pure puissance.', 'Dachte, ich hätte %thunderfury_link gehört, war aber nur der Klang reiner Awesomeness.', '我以为听到了%thunderfury_link，结果只是纯粹的震撼之声。', '', '', '', ''),
	(1008, 'thunderfury_spam', 'Oh, %thunderfury_link... Where *have* you been all my life?', 0, 0, '', 'Oh, %thunderfury_link ... Où as-tu été tout ce temps, ma belle épée ?', 'Oh, %thunderfury_link... Wo *warst* du mein ganzes Leben?', '哦，%thunderfury_link……我这辈子怎么才遇到你？', '', '', '', ''),
	(1009, 'thunderfury_spam', 'Did someone say %thunderfury_link? I think I need to go pick mine up.', 0, 0, '', '%thunderfury_link? Oh là là, j’entends toujours parler de cet incroyable objet! Je crois bien qu’il est temps pour moi d’aller le chercher.', 'Hat jemand %thunderfury_link gesagt? Ich glaub, ich hol mir mal meine.', '有人提到%thunderfury_link了？我觉得我也得去弄一把。', '', '', '', ''),
	(1010, 'thunderfury_spam', 'That was definitely the sound of %thunderfury_link! I can feel the epicness.', 0, 0, '', 'C’était certainement le son de %thunderfury_link ! Je peux sentir toute son épopée.', 'Das war definitiv der Sound von %thunderfury_link! Ich spür die Epicness.', '那绝对是%thunderfury_link的声音！我能感受到那份史诗感！', '', '', '', ''),
	(1011, 'thunderfury_spam', 'Is it just me, or does %thunderfury_link have a tendency to make everyone else *look* weak?', 0, 0, '', 'C’est moi ou bien %thunderfury_link a tendance à faire paraître les autres faibles?', 'Geht das nur mir so, oder lässt %thunderfury_link alle anderen *schwach aussehen*?', '是我一个人觉得吗，%thunderfury_link让其他人都显得*好弱*？', '', '', '', ''),
	(1012, 'thunderfury_spam', 'You know what they say... the louder the %thunderfury_link, the bigger the bragging rights!', 0, 0, '', 'Tu sais ce qu’on dit... plus le %thunderfury_link rugit, plus grand sont les droits de vantardise!', 'Wie man so sagt... je lauter %thunderfury_link, desto größer das Recht zu prahlen!', '都知道……%thunderfury_link声音越大，吹牛的资本就越足！', '', '', '', ''),
