	(1481, 'taunt', 'Were I like thee I’d throw away myself!', 0, 0, '', 'Si j’étais comme toi, je me jetterais en l’air !', 'Wäre ich wie du, würd ich mich selbst löschen!', '如果我像你一样，我早就把自己扔了！', '', '¡Si yo fuera como tú, me tiraría a la basura!', '', ''),
	(1482, 'taunt', 'O teach me <target>, how I should forget to think!', 0, 0, '', 'Oh, enseigne-moi, <target>, comment oublier de trop réfléchir!', 'Oh <target> lehre mich, wie ich das Denken vergesse!', '哦，教教我吧，<target>，怎样才能忘记思考！', '', '¡Oh, enséñame <target>, cómo debo olvidarme de pensar!', '', 'Научи меня, <target>, как забыть думать!'),
	(1483, 'taunt', 'Truly thou art damned, like an ill-roasted egg, all on one side!', 0, 0, '', 'Franchement, tu es foutu, comme un œuf mal cuit, tout d’un côté!', 'Ich hab schon Toiletten gesehen, die sauberer kämpfen als du.', '你真该死，就像个烤坏的蛋，全都焦在一边！', '', '¡Verdaderamente estás condenado, como un huevo mal asado, todo de un lado!', '', 'Истинно, ты проклят, как плохо прожаренное яйцо, с одной стороны!'),
	(1484, 'taunt', 'You starvelling, you eel-skin, you dried neat’s-tongue, you bull’s-pizzle, you stock-fish- O for breath to utter what is like thee!! -you tailor’s-yard, you sheath, you bow-case, you vile standing tuck!', 0, 0, '', '', 'Du verdammter Scheißkerl. Wo hast du dein Handwerk gelernt? Du dumme, verdammte Schlampe. Du Idiot. Wer hat dir gesagt, dass du mit Männern arbeiten kannst?', '你个饿殍、鳗鱼皮、干瘪牛舌、公牛鞭、腌鱼——哦，我要是有气力说出跟你有多像就好了！——你个裁缝尺、剑鞘、弓套、卑劣的站立家伙！', '', 'Estás muerto de hambre, piel de anguila, te secaste la lengua limpiamente, toro-pizzle, pescado-O para respirar pronunciar lo que es como tú !! ¡Tú, sastrería, vaina, estuche de arco, vil flaco de pie!', '', ''),
	(1485, 'taunt', 'Fie! Drop thee into the rotten mouth of Death!', 0, 0, '', 'Que le diable t’emporte dans la gueule pourrie de la Mort!', 'Wenn Unfähigkeit ’ne Klasse wäre, hättest du sie gemaxt.', '呸！掉进死亡的腐烂大嘴去吧！', '', '¡Fie! ¡Déjate caer en la podrida boca de la Muerte!', '', 'Фу! Брось себя в гнилую пасть Смерти!'),
	(1486, 'taunt', '<target>, you are a fishmonger!', 0, 0, '', '<target>, tu es poissonnier!', '<target> du dummes Arschfurz-Teppichladen-Arschloch', '<target>，你就是个卖鱼的！', '', '<target>, ¡eres un pescadero!', '', '<target>, ты торговец рыбой!'),
	(1487, 'taunt', 'I shall live to knock thy brains out!', 0, 0, '', 'Je vivrai pour te cogner le cerveau!', 'Ich lebe lang genug und dann nehm ich dir das Hirn raus!', '我会活着把你的脑浆打出来！', '', '¡Viviré para romperte los sesos!', '', 'Я доживу, чтобы выбить тебе мозги!'),
	(1488, 'taunt', 'Most shallow are you, <target>!! Thou art worms-meat in respect of a good piece of flesh, indeed!!', 0, 0, '', 'Comme tu es superficiel <target>!! Tu n’es que de la chair à vers comparé à un bon morceau de viande, en effet!!', 'Wenn <target> einen intelligenten Gedanken im Kopf hätte, würde er an Einsamkeit sterben.', '你真肤浅，<target>！！跟一块好肉比，你就是个虫子啃的货，的确如此！！', '', '¡¡Eres el más superficial, <target>!! ¡Eres carne de gusano con respecto a un buen trozo de carne, de hecho!', '', 'Ты очень поверхностен, <target>!! Ты корм для червей по сравнению с хорошим куском мяса!!'),
	(1489, 'taunt', 'Vile wretch! O <target>, thou odiferous hell-hated pignut!', 0, 0, '', 'Misérable vermine! Ô <target>, toi l’infâme pignouf puant des enfers!', 'Hör auf zu weinen, du winselnder Arsch, hör auf mit deinem Unsinn. Du bist nur die Nachgeburt, <target>.', '卑劣的混蛋！哦，<target>，你个地狱厌弃的臭猪头！', '', '¡Miserable vil! ¡Oh, <target>, fétido cerdo odiado por el infierno!', '', 'Подлый негодяй! О, <target>, ты зловонный, ненавистный к свиньям орех!'),
	(1490, 'taunt', '<target>! Thy kiss is as comfortless as frozen water to a starved snake!', 0, 0, '', '<target>! Ton baiser est aussi réconfortant que de l’eau gelée pour un serpent affamé!', '<target>! Wenn Gehirn Vogelkacke wäre, hättest du einen sauberen Käfig', '<target>！你的吻就像给一条饿蛇喂冰水一样毫无安慰！', '', '<target>! ¡Tu beso es tan desconsolador como el agua helada para una serpiente hambrienta!', '', '<target>! Твой поцелуй так же утешителен, как замёрзшая вода для голодной змеи!'),
	(1491, 'taunt', 'I scorn you, scurvy companion. What, you poor, base, rascally, cheating, lack-linen mate! Away, you moldy rogue, away!', 0, 0, '', 'Je vous méprise, misérable compagnon. Quoi, toi, pauvre, vil, scélérat, tricheur, compagnon usé de toile! Déguerpisse, espèce de coquin moisissure, déguerpisse!', 'Hör mal zu, du Vokuhila... warum zündest du nicht einfach dein Tampon an und sprengst deine Box in die Luft? Denn das ist der einzige Knall, den du kriegen wirst.', '我鄙视你，卑劣的家伙。什么，你个穷酸、下贱、无赖、骗子、破布般的同伴！滚吧，你个发霉的混账，滚！', '', 'Te desprecio, compañero escorbuto. ¡Qué, pobre, vil, pícaro, tramposo, compañero falto de lino! ¡Fuera, mohoso granuja, fuera!', '', 'Я презираю тебя, паршивый спутник. Что, ты бедный, низкий, мошеннический, безрубашечный приятель! Прочь, ты плесневелый негодяй, прочь!'),
	(1492, 'taunt', 'Out of my sight! Thou dost infect my eyes <target>!', 0, 0, '', 'Hors de ma vue! Tu infectes mes yeux <target>!', 'Verschwinde aus meiner Sicht <target>! Du verseuchst meine Augen!', '从我眼前消失！你污染了我的眼睛，<target>！', '', '¡Fuera de mi vista! ¡Me infectas los ojos <target>!', '', 'Прочь с глаз моих! Ты заражаешь мои глаза, <target>!'),
	(1493, 'taunt', 'PLAY TIME!!!!', 0, 0, '', 'L’HEURE DE LA MORT !', 'SPIELZEIT!!!!', '开战时间！！！！', '', '¡¡¡HORA DE JUGAR!!!!', '', 'ВРЕМЯ ИГРЫ!!!!'),
	(1494, 'taunt', 'None shall pass!', 0, 0, '', 'Vous ne passerez pas !', 'Niemand kommt vorbei!', '谁也别想通过！', '', '¡Ninguno pasará!', '', 'Никто не пройдёт!'),
	(1495, 'taunt', 'We’re under attack! A vast, ye swabs! Repel the invaders!', 0, 0, '', 'Nous sommes attaqués! Visez bien, bande de moussaillons! Repoussez les envahisseurs!', 'Wir werden angegriffen! Klar zum Gefecht, ihr Deckschrubber! Wehrt die Eindringlinge ab!', '我们遭到攻击！一大波敌人，蠢货们！击退入侵者！', '', '¡Estamos bajo ataque! ¡Un vasto, hisopos! ¡Repeler a los invasores!', '', ''),
	(1496, 'taunt', 'None may challenge the Brotherhood!', 0, 0, '', 'Personne ne peut défier la Confrérie!', 'Niemand darf die Bruderschaft herausfordern!', '没人能挑战兄弟会！', '', '¡Nadie puede desafiar a la Hermandad!', '', 'Никто не может бросить вызов Братству!'),
	(1497, 'taunt', 'Foolsss...Kill the one in the dress!', 0, 0, '', 'Imbéciles... Tuez celui en robe!', 'Narren... Tötet den im Kleid!', '蠢货们……干掉那个穿长袍的！', '', 'Tontosss... ¡Matad al del vestido!', '', 'Дураки... Убейте того, кто в платье!'),
	(1498, 'taunt', 'I’ll feed your soul to Hakkar himself! ', 0, 0, '', 'Je vais nourrir ton âme à Hakkar lui-même!', 'Ich werde deine Seele Hakkar selbst zum Fraß vorwerfen!', '我会把你的灵魂喂给哈卡本人！', '', '¡Le daré de comer con tu alma al mismísimo Hakkar! ', '', ''),
	(1499, 'taunt', 'Pride heralds the end of your world! Come, mortals! Face the wrath of the <randomfaction>!', 0, 0, '', '<randomfaction> m’apporte une grande fierté! Venez, mortels ! Affrontez la colère de <randomfaction>!', 'Stolz kündigt das Ende eurer Welt an! Kommt, Sterbliche! Stellt euch dem Zorn der <randomfaction>!', '骄傲预示着你们世界的终结！来吧，凡人！面对<randomfaction>的怒火！', '', '¡El orgullo anuncia el fin de tu mundo! ¡Venid, mortales! ¡Enfréntate a la ira de la <facción aleatoria>!', '', 'Гордость предвещает конец вашего мира! Идите, смертные! Столкнитесь с гневом !'),
	(1500, 'taunt', 'All my plans have led to this!', 0, 0, '', 'Tous mes projets ont mené à cela!', 'All meine Pläne haben zu diesem Moment geführt!', '我所有的计划都指向这一刻！', '', '¡Todos mis planes me han llevado a esto!', '', 'Все мои планы привели к этому!'),
	(1501, 'taunt', 'Ahh! More lambs to the slaughter!', 0, 0, '', 'Oh non! Encore des agneaux pour l’abattoir!', 'Ahh! Noch mehr Lämmer zur Schlachtbank!', '啊哈！又有羔羊来送死了！', '', '¡Ahh! ¡Más corderos al matadero!', '', 'Ах! Еще ягнята на заклание!'),
	(1502, 'taunt', 'Another day, another glorious battle!', 0, 0, '', 'Une autre journée, une autre bataille glorieuse !', 'Neuer Tag, neue glorreiche Schlacht!', '又是新的一天，又是一场光荣的战斗！', '', '¡Otro día, otra batalla gloriosa!', '', 'Еще один день, еще одна славная битва!'),
	(1503, 'taunt', 'So, business... or pleasure?', 0, 0, '', 'Alors, affaires... ou plaisir ?', 'Also, Geschäft... oder Vergnügen?', '那么，是公事……还是私事？', '', 'Entonces, ¿negocios... o placer?', '', 'Итак, дело... или удовольствие?'),
	(1504, 'taunt', 'You are not prepared!', 0, 0, '', 'Tu n’es pas prêt!', 'Ihr seid nicht vorbereitet!', '你们还没准备好！', '', '¡No estás preparado!', '', 'Вы не готовы!'),
	(1505, 'taunt', 'The <randomfaction>’s final conquest has begun! Once again the subjugation of this world is within our grasp. Let none survive! ', 0, 0, '', 'La dernière conquête de <randomfaction> a commencé! Encore une fois, la soumission de ce monde est à portée de main. Que personne ne survive!', 'Die letzte Eroberung der <randomfaction> hat begonnen! Wieder liegt die Unterwerfung dieser Welt in unseren Händen. Lasst keinen überleben!', '<randomfaction>的最终征服开始了！这个世界的臣服再次近在咫尺，一个也别想活！', '', '¡La conquista final de <randomfaction> ha comenzado! Una vez más, la subyugación de este mundo está a nuestro alcance. ¡Que nadie sobreviva! ', '', ''),
	(1506, 'taunt', 'Your death will be a painful one. ', 0, 0, '', 'Ta mort sera une douloureuse.', 'Euer Tod wird ein schmerzhafter sein.', '你的死会非常痛苦。', '', 'Tu muerte será dolorosa. ', '', 'Ваша смерть будет болезненной.'),
	(1507, 'taunt', 'Cry for mercy! Your meaningless lives will soon be forfeit. ', 0, 0, '', 'Pleurez miséricorde! Vos vies insignifiantes seront bientôt perdues.', 'Fleht um Gnade! Eure bedeutungslosen Leben sind bald verwirkt.', '求饶吧！你们无意义的生命马上就要终结了。', '', '¡Llora por piedad! Sus vidas sin sentido pronto se perderán. ', '', 'Просите о милости! Ваши бессмысленные жизни скоро будут потеряны.'),
	(1508, 'taunt', 'Abandon all hope! The <randomfaction> has returned to finish what was begun so many years ago. This time there will be no escape! ', 0, 0, '', 'Abandonne tout espoir! La <randomfaction> est de retour pour finir ce qui a été commencé il y a tant d’années. Cette fois, il n’y aura pas d’échappatoire!', 'Gebt alle Hoffnung auf! Die <randomfaction> ist zurückgekehrt, um zu beenden, was vor so vielen Jahren begann. Diesmal gibt es kein Entkommen!', '放弃所有希望吧！<randomfaction>回来了，要完成多年前未竟的事业。这次，你们无处可逃！', '', '¡Abandona toda esperanza! La <randomfaction> ha regresado para terminar lo que comenzó hace tantos años. ¡Esta vez no habrá escapatoria! ', '', 'Оставьте все надежды!  вернулся, чтобы завершить то, что было начато много лет назад. На этот раз не будет побега!'),
	(1509, 'taunt', 'Alert! You are marked for Extermination! ', 0, 0, '', 'Alerte ! Vous êtes désigné pour extermination !', 'Alarm! Ihr seid zur Auslöschung markiert!', '警报！你们被标记为清除目标！', '', '¡Alerta! ¡Estás marcado para el exterminio! ', '', 'Внимание! Вы помечены для уничтожения!'),
	(1510, 'taunt', 'The <subzone> is for guests only...', 0, 0, '', 'Le <subzone> est réservé aux invités uniquement...', 'Die <subzone> ist nur für Gäste...', '<subzone>仅对访客开放……', '', 'La <subzone> es solo para invitados...', '', ' предназначена только для гостей...'),
	(1511, 'taunt', 'Ha ha ha! You are hopelessly outmatched!', 0, 0, '', 'Ha ha ha! Tu es totalement dépassé!', 'Hahaha! Ihr seid hoffnungslos unterlegen!', '哈哈哈！你们完全不是对手！', '', '¡Ja, ja, ja! ¡Estás irremediablemente superado!', '', 'Ха-ха-ха! Вы безнадежно не на уровне!'),
	(1512, 'taunt', 'I will crush your delusions of grandeur! ', 0, 0, '', 'Je vais briser tes illusions de grandeur!', 'Ich werde euren Größenwahn zerschmettern!', '我会粉碎你自大的幻想！', '', '¡Aplastaré tus delirios de grandeza! ', '', 'Я сокрушу ваши иллюзии величия!'),
	(1513, 'taunt', 'Forgive me, for you are about to lose the game.', 0, 0, '', 'Pardonnez-moi, mais vous êtes sur le point de perdre la partie.', 'Verzeiht mir, denn ihr werdet gleich das Spiel verlieren.', '原谅我，因为你们马上就要输了。', '', 'Perdóname, porque estás a punto de perder el juego.', '', 'Простите меня, ведь вы собираетесь проиграть игру.'),
	(1514, 'taunt', 'Struggling only makes it worse.', 0, 0, '', 'Se battre ne fait qu’empirer les choses.', 'Wehren macht es nur schlimmer.', '挣扎只会让事情变得更糟。', '', 'La lucha solo lo empeora.', '', 'Борьба только усугубляет ситуацию.'),
	(1515, 'taunt', 'Vermin! Leeches! Take my blood and choke on it!', 0, 0, '', 'Créatures immondes ! Sangsues ! Prenez mon sang et étouffez-y !', 'Ungeziefer! Blutegel! Saugt mein Blut und erstickt daran!', '害虫！吸血鬼！喝我的血，噎死你们！', '', '¡Alimañas! ¡Sanguijuelas! ¡Toma mi sangre y atragantate con ella!', '', 'Паразиты! Пиявки! Берите мою кровь и подавитесь ею!'),
	(1516, 'taunt', 'Not again... NOT AGAIN!', 0, 0, '', 'Pas encore... PAS ENCORE !', 'Nicht schon wieder... NICHT SCHON WIEDER!', '别再来了……别再来了！', '', 'No otra vez... ¡NO OTRA VEZ!', '', 'Опять... ЕЩЕ РАЗ!'),
	(1517, 'taunt', 'My blood will be the end of you!', 0, 0, '', 'Mon sang sera ta fin!', 'Mein Blut wird euer Ende sein!', '我的鲜血将是你的终结！', '', '¡Mi sangre será tu fin!', '', 'Моя кровь станет вашим концом!'),
	(1518, 'taunt', 'Good, now you fight me!', 0, 0, '', 'Bien, maintenant combat moi !', 'Gut, jetzt kämpfst du gegen mich!', '好极了，现在来跟我打吧！', '', 'Bien, ¡ahora pelea conmigo!', '', 'Хорошо, теперь ты сразишься со мной!'),
	(1519, 'taunt', 'Get da move on, guards! It be killin’ time!', 0, 0, '', 'Allez, les gardes, on se presse! C’est l’heure de tuer!', 'Macht hinne, Wachen! Es ist Zeit zum Töten!', '快点动起来，卫兵们！是时候大开杀戒了！', '', '¡Muévanse, guardias! ¡Será para matar el tiempo!', '', ''),
	(1520, 'taunt', 'Don’t be delayin’ your fate. Come to me now. I make your sacrifice quick.', 0, 0, '', 'Ne retarde pas ton destin. Viens à moi maintenant. Je rends ton sacrifice rapide.', 'Zögert euer Schicksal nicht hinaus. Kommt jetzt zu mir. Ich mache euer Opfer kurz.', '别拖延你的命运。现在过来，我会让你的牺牲快一点。', '', 'No demores tu destino. Ven a mí ahora. Hago que tu sacrificio sea rápido.', '', ''),
	(1521, 'taunt', 'You be dead soon enough!', 0, 0, '', 'Tu seras bientôt mort !', 'Bald seid ihr tot!', '你很快就会死翘翘！', '', '¡Estarás muerto lo suficientemente pronto!', '', 'Ты скоро будешь мертв!'),
	(1522, 'taunt', 'Mua-ha-ha!', 0, 0, '', 'Mua-ha-ha!', 'Mu-ha-ha!', '哇哈哈哈！', '', '¡Mua-ja-ja!', '', 'Муа-ха-ха!'),
	(1523, 'taunt', 'I be da predator! You da prey...', 0, 0, '', 'Je suis le prédateur! Tu es la proie...', 'Ich bin der Jäger! Ihr seid die Beute...', '我是猎手！你是猎物……', '', '¡Soy un depredador! Eres presa...', '', 'Я хищник! Ты жертва...'),
	(1524, 'taunt', 'You gonna leave in pieces!', 0, 0, '', 'Tu vas finir en morceaux !', 'Ihr werdet diesen Ort in Stücken verlassen!', '你会碎成渣离开这里！', '', '¡Te vas a ir en pedazos!', '', 'Ты уйдешь в кусках!'),
	(1525, 'taunt', 'Death comes. Will your conscience be clear? ', 0, 0, '', 'La mort arrive. Est-ce que ta conscience sera claire ?', 'Der Tod naht. Wird euer Gewissen rein sein?', '死亡降临了。你的良心能安宁吗？', '', 'La muerte llega. ¿Tu conciencia estará limpia? ', '', 'Смерть приходит. Будет ли твоя совесть чиста?'),
	(1526, 'taunt', 'Your behavior will not be tolerated.', 0, 0, '', 'Votre comportement ne sera pas toléré.', 'Euer Verhalten wird nicht toleriert.', '你的行为不可容忍。', '', 'Tu comportamiento no será tolerado', '', 'Ваше поведение не будет терпимо.'),
	(1527, 'taunt', 'The Menagerie is for guests only.', 0, 0, '', 'La Ménagerie est réservée aux invités seulement.', 'Die Menagerie ist nur für Gäste.', '展览馆仅对访客开放。', '', 'The Menagerie es solo para invitados', '', 'Менажерия предназначена только для гостей.'),
	(1528, 'taunt', 'Hmm, unannounced visitors, Preparations must be made... ', 0, 0, '', 'Des visiteurs non annoncés, il me faut faire des préparatifs...', 'Hmm, unangekündigte Besucher. Vorbereitungen müssen getroffen werden...', '嗯，未经通报的访客，必须做好准备……', '', 'Hmm, visitantes inesperados, se deben hacer preparativos... ', '', 'Хмм, незваные гости, нужно подготовиться...'),
	(1529, 'taunt', 'Hostile entities detected. Threat assessment protocol active. Primary target engaged. Time minus thirty seconds to re-evaluation.', 0, 0, '', 'Entités hostiles détectées. Protocole d’évaluation des menaces activé. Cible principale engagée. Temps moins trente secondes avant réévaluation.', 'Feindliche Einheiten entdeckt. Bedrohungsanalyse-Protokoll aktiv. Primärziel erfasst. Zeit minus dreißig Sekunden bis zur Neubewertung.', '侦测到敌对实体。威胁评估协议已激活。主要目标锁定。距离重新评估还有三十秒。', '', 'Entidades hostiles detectadas. Protocolo de evaluación de amenazas activo. Objetivo principal comprometido. Tiempo menos treinta segundos para la reevaluación.', '', 'Обнаружены враждебные сущности. Протокол оценки угрозы активирован. Основная цель захвачена. Время до повторной оценки - тридцать секунд.'),
	(1530, 'taunt', 'New toys? For me? I promise I won’t break them this time!', 0, 0, '', 'De nouveaux jouets ? Pour moi ? Je te promets que cette fois, je ne les casserai pas !', 'Neue Spielzeuge? Für mich? Ich verspreche, ich mach sie diesmal nicht kaputt!', '新玩具？给我玩的？我保证这次不会弄坏它们！', '', '¿Juguetes nuevos? ¿Para mi? ¡Te prometo que no los romperé esta vez!', '', ''),
	(1531, 'taunt', 'I’m ready to play!', 0, 0, '', 'Je suis prêt à jouer !', 'Ich bin bereit zu spielen!', '我准备好玩一玩了！', '', '¡Estoy listo para jugar!', '', ''),
	(1532, 'taunt', 'Shhh... it will all be over soon.', 0, 0, '', 'Chut... tout sera bientôt fini.', 'Pssst... gleich ist alles vorbei.', '嘘……这一切很快就会结束。', '', 'Shhh... todo terminará pronto.', '', 'Шшш... скоро все закончится.'),
	(1533, 'taunt', 'Aaaaaughibbrgubugbugrguburgle!', 0, 0, '', 'Aaaaaughibbrgubugbugrguburgle!', 'Aaaaaughibbrgubugbugrguburgle!', '啊啊啊啊咕噜咕噜咕噜咕！', '', '¡Aaaaaughibbrgubugbugrguburgle!', '', 'Ааааагхиббргубугбугрубгл!'),
	(1534, 'taunt', 'RwlRwlRwlRwl!', 0, 0, '', 'RwlRwlRwlRwl!', 'RwlRwlRwlRwl!', '嗷嗷嗷嗷！', '', 'RwlRwlRwlRwl!', '', 'РвлРвлРвлРвл!'),
	(1535, 'taunt', 'You too, shall serve!', 0, 0, '', 'Toi aussi, tu serviras !', 'Auch du wirst dienen!', '你也一样，必须效忠！', '', '¡Tú también, debes servir!', '', 'Ты тоже будешь служить!'),
	(1536, 'taunt', 'Tell me... tell me everything!  Naughty secrets! I’ll rip the secrets from your flesh!', 0, 0, '', 'Dis-moi... dis-moi tout ! Les petits secrets coquins ! Je vais arracher les secrets de ta chair !', 'Sag es mir... sag mir alles, Geheimnisse und Privatsachen! Ich reiße dir die Infos aus dem Fleisch!', '告诉我……把一切都告诉我！那些小秘密！我会从你的血肉中撕出真相！', '', 'Cuéntame... ¡cuéntame todo! ¡Secretos traviesos! ¡Arrancaré los secretos de tu carne!', '', ''),
	(1537, 'taunt', 'Prepare yourselves, the bells have tolled! Shelter your weak, your young and your old! Each of you shall pay the final sum! Cry for mercy, the reckoning has come!', 0, 0, '', 'Préparez-vous, les cloches ont sonné ! Protégez vos faibles, vos jeunes et vos anciens ! Chacun d’entre vous paiera le prix final ! Pleurez miséricorde, l’heure du jugement est arrivée!', 'Macht euch bereit, die Glocken haben geläutet! Bringt die Schwachen, die Jungen und die Alten in Sicherheit! Jeder von euch zahlt den letzten Preis! Fleht um Gnade, die Abrechnung ist gekommen!', '准备好吧，丧钟已敲响！保护你们的弱者、孩子和老人！你们每个人都将付出最终代价！哭求怜悯吧，清算时刻到了！', '', '¡Prepárense, las campanas han doblado! ¡Abriga a tus débiles, a tus jóvenes ya tus viejos! ¡Cada uno de ustedes pagará la suma final! Clama por misericordia, el ajuste de cuentas ha llegado!', '', 'Приготовьтесь, колокола прозвучали! Укройте своих слабых, молодых и старых! Каждый из вас заплатит окончательную цену! Просите о милости, расплата пришла!'),
	(1538, 'taunt', 'Where in Bonzo’s brass buttons am I?', 0, 0, '', 'Où diable suis-je?', 'Wo, bei Bonzos Messingknöpfen, bin ich?', '我到底在邦佐的黄铜扣子哪里？', '', '¿Dónde estoy en los botones de latón de Bonzo?', '', ''),
	(1539, 'taunt', 'I can bear it no longer! Goblin King! Goblin King! Wherever you may be! Take this <target> far away from me!', 0, 0, '', 'Je n’en peux plus! Roi des Gobelins! Roi des Gobelins! Où que tu sois! Emmène cette %cible% loin de moi!', 'Ich ertrage es nicht länger! Goblinkönig! Goblinkönig! Wo immer du bist! Nimm diesen <target> weit weg von mir!', '我再也受不了了！地精之王！地精之王！不管你在哪！把这个<target>带离我远点！', '', '¡No puedo soportarlo más! ¡Rey de los duendes! ¡Rey de los duendes! ¡WHERE quiera que estés! ¡Lleva a este <target> lejos de mí!', '', 'Я больше не могу это терпеть! Король гоблинов! Король гоблинов! Где бы ты ни был! Унеси этого  далеко от меня!'),
	(1540, 'taunt', 'You have thirteen hours in which to solve the labyrinth, before your baby brother becomes one of us... forever.', 0, 0, '', 'Tu as treize heures pour résoudre le labyrinthe, avant que ton petit frère ne devienne l’un d’entre nous... pour toujours.', 'Ihr habt dreizehn Stunden, um das Labyrinth zu lösen, bevor euer kleiner Bruder einer von uns wird... für immer.', '你有十三小时来解开迷宫，否则你的小弟弟将永远成为我们的一员……', '', 'Tienes trece horas para resolver el laberinto, antes de que tu hermanito se convierta en uno de nosotros... para siempre', '', 'У вас есть тринадцать часов, чтобы решить лабиринт, прежде чем ваш младший брат станет одним из нас... навсегда.'),
	(1541, 'taunt', 'So, the <subzone> is a piece of cake, is it? Well, let’s see how you deal with this little slice... ', 0, 0, '', 'Alors, la <subzone> est du gâteau, vous dites? Hmm, voyons comment vous vous en sortez avec cette petite portion...', 'Also, die <subzone> ist Kinderkram, ja? Dann sehen wir mal, wie ihr dieses kleine Stückchen verdaut...', '所以，<subzone>对你来说是小菜一碟，对吧？好吧，看看你怎么应付这小块“蛋糕”……', '', 'Entonces, la <subzone> es pan comido, ¿verdad? Bueno, veamos cómo lidias con esta pequeña porción... ', '', ''),
	(1542, 'taunt', 'Back off, I’ll take you on, headstrong to take on anyone, I know that you are wrong, and this is not where you belong', 0, 0, '', 'Alors, recule, je vais m’occuper de toi, déterminé à affronter n’importe qui, je sais que tu as tort, et ce n’est pas là que tu appartiens', 'Weiche! Ich stelle mich jedem Kampf. Du irrst dich, dies ist nicht dein Revier.', '退后，我来对付你，胆大包天敢挑战任何人，我知道你错了，这里不是你该来的地方', '', 'Atrás, te enfrentaré, testarudo para enfrentar a cualquiera, sé que estás equivocado, y este no es el lugar al que perteneces', '', ''),
	(1543, 'taunt', 'Show me whatcha got!', 0, 0, '', 'Montre-moi ce que t’as dans le ventre!', 'Zeig, was du drauf hast!', '让我瞧瞧你有啥能耐！', '', '¡Muéstrame lo que tienes!', '', 'Покажи, что у тебя есть!'),
	(1544, 'taunt', 'To the death!', 0, 0, '', '% Sorry, I can’t translate that.', 'Bis zum Tod!', '决一死战！', '', '¡Hasta la muerte!', '', 'До смерти!'),
	(1545, 'taunt', 'Twin blade action, for a clean close shave every time.', 0, 0, '', 'Lame jumelle, pour un rasage de près impeccable à chaque fois.', 'Zweiklingen-Action für eine glatte und saubere Rasur jedes mal.', '双刃出击，每次都能干净利落！', '', 'Acción de cuchilla doble, para un afeitado limpio y apurado en todo momento.', '', 'Двойное лезвие, для чистого бритья каждый раз.'),
	(1546, 'taunt', 'Bring it on!', 0, 0, '', 'Allez, viens ici !', 'Los, komm schon!', '来吧！', '', '¡Adelante!', '', 'Давай!'),
	(1547, 'taunt', 'You’re goin’ down!', 0, 0, '', 'Tu vas tomber !', 'Du gehst drauf!', '你死定了！', '', '¡Vas a caer!', '', ''),
	(1548, 'taunt', 'Stabby stab stab!', 0, 0, '', 'Stabby stab stab!', 'Stich, stich, stich!', '刺刺刺！', '', '¡Puñalada puñalada puñalada!', '', 'Ударь, ударь, ударь!'),
	(1549, 'taunt', 'Let’s get this over quick, time is mana.', 0, 0, '', 'Finissons-en vite , le temps c’est du mana.', 'Machen wir das schnell, Zeit ist Mana.', '咱们速战速决，时间就是魔法！', '', 'Terminemos con esto rápido, el tiempo es maná.', '', ''),
	(1550, 'taunt', 'I do not think you realise the gravity of your situation.', 0, 0, '', 'Tu ne réalise pas encore la gravité de ta situation.', 'Ich glaube nicht, dass ihr die Schwere eurer Lage begreift.', '我想你还没意识到你处境的严重性。', '', 'No creo que te des cuenta de la gravedad de tu situación.', '', 'Я не думаю, что вы осознаете серьезность вашей ситуации.'),
	(1551, 'taunt', 'I will bring honor to my family and my kingdom!', 0, 0, '', 'Je vais apporter honneur à ma famille et à mon royaume!', 'Ich bringe meiner Familie und meinem Königreich Ehre!', '我会为我的家族和王国带来荣耀！', '', '¡Llevaré honor a mi familia y mi reino!', '', 'Я принесу честь своей семье и своему королевству!'),
	(1552, 'taunt', 'Light, give me strength!', 0, 0, '', 'Lumière, donne-moi de la force!', 'Licht, gib mir Stärke!', '圣光，赐予我力量！', '', '¡Luz, dame fuerza!', '', 'Свет, дай мне силу!'),
	(1553, 'taunt', 'My church is the field of battle - time to worship...', 0, 0, '', 'Mon terrain de bataille, c’est mon église - il est temps de rendre hommage...', 'Meine Kirche ist das Schlachtfeld, Zeit zum Gottesdienst...', '战场就是我的教堂——是时候膜拜了……', '', 'Mi iglesia es el campo de batalla - hora de adorar...', '', 'Моя церковь - это поле битвы - время поклоняться...'),
	(1554, 'taunt', 'I hold you in contempt...', 0, 0, '', 'Je te méprise...', 'Ich verachte euch...', '我鄙视你……', '', 'Te tengo en desacato...', '', 'Я держу тебя в презрении...'),
	(1555, 'taunt', 'Face the hammer of justice!', 0, 0, '', 'Affronte le marteau de la justice!', 'Stellt euch dem Hammer der Gerechtigkeit!', '面对正义之锤吧！', '', '¡Enfréntate al martillo de la justicia!', '', 'Столкнись с молотом справедливости!'),
	(1556, 'taunt', 'Prove your worth in the test of arms under the Light!', 0, 0, '', 'Prouve ta valeur dans le test des armes sous la Lumière!', 'Beweist euren Wert in der Prüfung der Waffen im Lichte!', '在圣光的见证下证明你的武艺价值！', '', '¡Demuestra tu valía en la prueba de las armas bajo la Luz!', '', 'Докажи свою ценность в испытании оружием под Светом!'),
	(1557, 'taunt', 'All must fall before the might and right of my cause, you shall be next!', 0, 0, '', 'Tous doivent tomber devant la puissance et la justesse de ma cause, tu seras le prochain!', 'Alles wird vor der Macht und der Gerechtigkeit meiner Sache fallen. Ihr werdet der Nächste sein!', '所有人都将在我的正义与力量前倒下，你就是下一个！', '', 'Todo debe caer ante el poder y el derecho de mi causa, ¡tú serás el próximo!', '', 'Все должны пасть перед могуществом и правом моего дела, ты будешь следующим!'),
	(1558, 'taunt', 'Prepare to die!', 0, 0, '', 'Prépare-toi à mourir!', 'Bereitet euch aufs Sterben vor!', '准备受死吧！', '', '¡Prepárate para morir!', '', 'Приготовься умереть!'),
	(1559, 'taunt', 'The beast with me is nothing compared to the beast within...', 0, 0, '', 'La bête qui est avec moi n’est rien comparée à la bête qui est en moi...', 'Die Bestie an meiner Seite ist nichts gegen die Bestie in mir...', '我身边的野兽与我内心的猛兽相比简直不值一提……', '', 'La bestia conmigo no es nada comparada con la bestia interior...', '', 'Зверь со мной ничто по сравнению с зверем внутри...'),
	(1560, 'taunt', 'Witness the firepower of this fully armed huntsman!', 0, 0, '', 'Découvrez la puissance de feu de ce chasseur entièrement armé!', 'Erlebt die Feuerkraft dieses voll bewaffneten Jägers!', '见识一下全副武装猎人的火力吧！', '', '¡Sea testigo de la potencia de fuego de este cazador completamente armado!', '', 'Стань свидетелем огневой мощи этого полностью вооруженного охотника!'),
	(1561, 'critical health', 'Heal me! Quick!', 0, 0, '', 'Je vais te soigner tout de suite !', 'Heilt mich! Schnell!', '快治疗我！快点！', '', '¡Cúrame! ¡Rápido!', '', 'Исцели меня! Быстро!'),
	(1562, 'critical health', 'Almost dead! Heal me!', 0, 0, '', 'Presque mort ! Soignez-moi !', 'Fast tot! Heilt mich!', '快不行了！治疗我！', '', '¡Estoy casi muerto! ¡Cúrame!', '', 'Почти мертв! Исцели меня!'),
	(1563, 'critical health', 'Help! Heal me!', 0, 0, '', 'S’il te plaît, aide-moi! Soigne-moi!', 'Hilfe! Heilt mich!', '救命！治疗我！', '', '¡Ayuda! ¡Cúrame!', '', 'Помогите! Исцели меня!'),
	(1564, 'critical health', 'Somebody! Heal me!', 0, 0, '', 'Quelqu’un ! Soigne-moi !', 'Irgendwer! Heilt mich!', '谁来！治疗我！', '', '¡Alguien! ¡Cúrame!', '', 'Кто-нибудь! Исцели меня!'),
	(1565, 'critical health', 'Heal! Heal! Heal!', 0, 0, '', 'Guérir! Guérir! Guérir!', 'Heal! Heal! Heal!', '治疗！治疗！治疗！', '', '¡Curame! ¡Saname! ¡Socorro!', '', 'Исцели! Исцели! Исцели!'),
	(1566, 'critical health', 'I am dying! Heal! Aaaaarhg!', 0, 0, '', 'Je meurs! Au secours! Aaaaarhg!', 'Ich sterbe! Heal! Aaaaarhg!', '我要死了！治疗！啊啊啊啊！', '', '¡Me estoy muriendo! ¡Saname! ¡Aaaaarhg!', '', 'Я умираю! Исцели! Ааааргх!'),
	(1567, 'critical health', 'Heal me!', 0, 0, '', 'Soigne moi !', 'Heal mich!', '快治疗我！', '', '¡Cúrame!', '', 'Исцели меня!'),
	(1568, 'critical health', 'I will die. I will die. I will die. Heal!', 0, 0, '', 'Je vais mourir. Je vais mourir. Je vais mourir. Soigne-moi !', 'Ich sterbe. Ich sterbe. Ich sterbe. Heal!', '我要死了！我要死了！快治疗！', '', 'Voy a morir. Voy a morir. Voy a morir. ¡Saname!', '', 'Я умру. Я умру. Я умру. Исцели!'),
	(1569, 'critical health', 'Healers, where are you? I am dying!', 0, 0, '', 'Healers, où êtes-vous? Je suis en train de mourir!', 'Heiler, wo seid ihr? Ich sterbe!', '治疗呢？你们在哪儿？我快挂了！', '', 'Sanadores, ¿dónde estais? ¡Me estoy muriendo!', '', 'Целители, где вы? Я умираю!'),
	(1570, 'critical health', 'Oh the pain. Heal me quick!', 0, 0, '', 'Oh la douleur. Guérissez-moi vite!', 'Oh, der Schmerz. Heilt mich schnell!', '哎哟，好痛！快给我治疗！', '', 'Ouch, qué dolor. ¡Cúrame rápido!', '', 'О, боль. Исцели меня быстро!'),
	(1571, 'low health', 'Need heal', 0, 0, '', 'Besoin de soins', 'Brauche Heal', '需要治疗！', '', 'Necesito una cura', '', 'Нужна исцеление'),
	(1572, 'low health', 'Low health', 0, 0, '', 'Faible santé', 'HP low', '血量低了！', '', 'Salud baja', '', 'Низкое здоровье'),
	(1573, 'low health', 'Drop a heal. Please.', 0, 0, '', 'HEAL. S’il te plaît.', 'Gebt mal nen Heal. Bitte.', '来个治疗，求你了！', '', 'Una sanación por favor.', '', 'Сделай исцеление. Пожалуйста.'),
	(1574, 'low health', 'Could somebody drop a heal on me?', 0, 0, '', 'Est-ce que quelqu’un pourrait me soigner?', 'Kann mir jemand nen Heal geben?', '谁能给我加点血啊？', '', '¿Alguien podría curarme?', '', 'Может кто-нибудь исцелить меня?'),
	(1575, 'low health', 'Hey! Better heal me now than rez later', 0, 0, '', 'Salut! Mieux vaut me soigner maintenant que me ressusciter plus tard.', 'Hey! Lieber jetzt heilen als später zu rezzen', '嘿！现在治好我总比待会儿复活强吧！', '', '¡Oye! Mejor curarme ahora que resucitarme después', '', 'Эй! Лучше исцели меня сейчас, чем воскрешать позже.'),
	(1576, 'low health', 'I am sorry. Need another heal', 0, 0, '', 'Je suis désolé. J’ai besoin d’une autre guérison.', 'Sorry. Brauche noch einen Heal', '抱歉，又需要治疗了！', '', 'Lo siento. Necesito otra curación', '', 'Извини. Нужна еще одна исцеление.'),
	(1577, 'low health', 'Damn mobs. Heal me please', 0, 0, '', 'Maudits mobs. Guéris moi s’il te plait', 'Verdammte Mobs. Heal mich bitte', '该死的怪物，拜托治疗一下！', '', '¡Malditos bichos! ¡Una curita por favor!', '', 'Черт возьми, мобы. Исцели меня, пожалуйста.'),
	(1578, 'low health', 'One more hit and I am done for. Heal please', 0, 0, '', 'Un coup de plus et c’est fini. Guéris moi s’il te plait', 'Noch ein Treffer und ich bin hinüber. Heal bitte', '再挨一下我就完了，求治疗！', '', 'Un golpe más y estoy acabado. Cura por favor', '', 'Еще один удар, и я пропал. Исцели, пожалуйста.'),
	(1579, 'low health', 'Are there any healers?', 0, 0, '', 'Y a-t-il des guérisseurs?', 'Heiler da?', '有治疗吗？', '', '¿Hay sanadores?', '', 'Есть ли целители?'),
	(1580, 'low health', 'Why do they always punch me in the face? Need heal', 0, 0, '', 'Pourquoi est-ce qu’ils me frappent toujours au visage? J’ai besoin de guérison', 'Warum hauen die mir immer ins Gesicht? Brauche Heal', '为什么总是打我脸？需要治疗！', '', '¿Por qué siempre me golpean en la cara? Necesito sanacion', '', 'Почему они всегда бьют меня в лицо? Нужна исцеление.'),
	(1581, 'low health', 'Can anybody heal me a bit?', 0, 0, '', 'Soignez moi, même juste un peu ?', 'Kann mich wer ein bisschen heilen?', '谁能给我加一点血？', '', '¿Alguien puede curarme un poco?', '', 'Может кто-нибудь немного исцелить меня?'),
	(1582, 'low mana', 'OOM', 0, 0, '', 'Plus de mana !', 'OOM', '没蓝了！', '', 'No tengo mana!', '', 'OOM'),
	(1583, 'low mana', 'I am out of mana', 0, 0, '', 'Je n’ai plus de mana', 'Kein Mana mehr', '我没蓝了！', '', 'No tengo maná', '', 'У меня закончилась мана'),
	(1584, 'low mana', 'Damn I wasted all my mana on this', 0, 0, '', 'Damn j’ai gaspillé toute ma mana sur ça.', 'Verdammt, dafür hab ich mein ganzes Mana verballert', '该死，我的蓝全浪费在这上面了！', '', 'Me cago en todo! Malgasté todo mi maná enseguida', '', 'Черт, я потратил всю свою ману на это'),
	(1585, 'low mana', 'You should wait until I drink or regenerate my mana', 0, 0, '', 'Tu devrais attendre que je boive ou régénère ma mana.', 'Wartet bis ich trinke oder mein Mana wieder da ist', '等我喝点水或者回点蓝再继续吧！', '', 'Deberías esperar hasta que beba o regenere mi maná', '', 'Тебе стоит подождать, пока я выпью или восстановлю свою ману'),
	(1586, 'low mana', 'Low mana', 0, 0, '', 'Bas niveau de mana.', 'Mana low', '蓝量低了！', '', 'Maná bajo', '', 'Низкая мана'),
	(1587, 'low mana', 'No mana. Again?', 0, 0, '', 'Pas de mana. Encore ?', 'Kein Mana. Schon wieder?', '没蓝了，又是这样？', '', 'Sin maná. ¿Otra vez?', '', 'Нет маны. Снова?'),
	(1588, 'low mana', 'Low mana. Wanna drink', 0, 0, '', 'Plus de mana, je prendrai bien un peu d eau', 'Mana low. Muss trinken', '蓝量低了，想喝点水！', '', 'Maná bajo. Quiero beber', '', 'Низкая мана. Хочу выпить.'),
	(1589, 'low mana', 'Do we have a vending machine? Out of mana again', 0, 0, '', 'Nous avons une machine distributrice ? Encore à court de mana.', 'Haben wir nen Getränkeautomaten? Wieder OOM', '有自动售卖机吗？又没蓝了！', '', '¿Tenemos una máquina expendedora? Sin maná otra vez', '', 'У нас есть торговый автомат? Снова нет маны.'),
	(1590, 'low mana', 'My mana is history', 0, 0, '', 'Mon mana est à sec.', 'Mein Mana ist Geschichte', '我的蓝已经见底了！', '', 'Mi maná es historia', '', 'Моя мана в истории.'),
	(1591, 'low mana', 'I’d get some drinks next time. Out of mana', 0, 0, '', 'Je prendrai des verres la prochaine fois. Plus de mana.', 'Ich besorge mir nächstes mal Drinks. OOM', '下次一定要多带点喝的，没蓝了！', '', '¡No tengo maná! Tengo que comprar bebidas la próxima vez...', '', ''),
	(1592, 'low mana', 'Where is my mana?', 0, 0, '', 'Oh là là, désolé, mais je ne sais pas du tout où se trouve ta mana. As-tu vérifié tous tes sacs et tes poches? Peut-être que tu l’as laissé quelque part dans la maison ou dans ton sac à dos. Il est toujours embêtant de perdre quelque chose d’aussi précieux que sa mana, j’espère que tu vas la retrouver bientôt!', 'Wo ist mein Mana?', '我的蓝去哪儿了？', '', '¿Dónde está mi maná?', '', 'Где моя мана?'),
	(1593, 'low ammo', 'I have few <ammo> left!', 0, 0, '', 'Il ne me reste que quelques <ammo> !', 'Ich habe nur noch wenig <ammo>!', '我只剩一点<ammo>了！', '', '¡Me quedan pocas <ammo>!', '', 'У меня осталось немного !'),
	(1594, 'low ammo', 'I need more <ammo>!', 0, 0, '', 'J’ai besoin de plus de <ammo>!', 'Ich brauche mehr <ammo>!', '我需要更多的<ammo>！', '', '¡Necesito más <ammo>!', '', 'Мне нужно больше !'),
	(1595, 'low ammo', '100 <ammo> left!', 0, 0, '', 'Il me reste 100 <ammo> !', 'Noch 100 <ammo>!', '还剩100个<ammo>！', '', '¡Quedan 100 <ammo>!', '', '100  осталось!'),
	(1596, 'no ammo', 'That’s it! No <ammo>!', 0, 0, '', 'C’est ça! Pas de <ammo>!', 'Das war es! Keine <ammo> mehr!', '完了！没<ammo>了！', '', '¡Eso es todo! ¡Sin <ammo>!', '', ''),
	(1597, 'no ammo', 'And you have my bow... Oops, no <ammo>!', 0, 0, '', 'Et vous avez mon arc... Oops, pas de <munitions> !', 'Und ihr habt meinen Bogen... ups, keine <ammo>!', '你拿了我的弓……呃，没<ammo>了！', '', 'Y tú tienes mi arco... ¡Uy, sin <ammo>!', '', 'И у тебя есть мой лук... Ой, нет !'),
	(1598, 'no ammo', 'Need ammo!', 0, 0, '', 'Besoin de munitions !', 'Brauche <ammo>!', '需要弹药！', '', '¡Necesito munición!', '', 'Нужна патроны!'),
	(1599, 'aoe', 'Oh god!', 0, 0, '', 'Oh mon Dieu!', 'Oh Gott!', '天哪！', '', '¡Oh, Dios!', '', 'О боже!'),
	(1600, 'aoe', 'I am scared', 0, 0, '', 'Je suis effrayé.', 'Ich habe Angst', '我好害怕！', '', 'Tengo miedo', '', 'Мне страшно'),
	(1601, 'aoe', 'We are done for', 0, 0, '', 'Nous sommes foutus.', 'Wir sind am Arsch.', '我们完了！', '', 'Hemos terminado', '', 'Мы пропали'),
	(1602, 'aoe', 'This is over', 0, 0, '', 'C’est terminé', 'Das wars.', '这下完了！', '', 'Esto se acabó', '', 'Это закончено'),
	(1603, 'aoe', 'This ends now', 0, 0, '', 'Cela se termine maintenant.', 'Hier ist jetzt Schluss.', '现在就结束了！', '', 'Esto termina ahora', '', 'Это заканчивается сейчас'),
	(1604, 'aoe', 'Could somebody cast blizzard or something?', 0, 0, '', 'Est-ce que quelqu’un pourrait lancer une tempête de neige ou quelque chose du genre, s’il vous plaît?', 'Kann mal wer Blizzard anrufen?', '谁能扔个暴风雪啥的吗？', '', '¿Alguien podría lanzar ventisca o algo así?', '', 'Может кто-нибудь вызвать метель или что-то подобное?'),
	(1605, 'aoe', 'Damn. The tank aggroed all the mobs around', 0, 0, '', 'Maudit tank a attiré tous les ennemis autour.', 'Verdammt. Der Tank hat alle Mobs gepullt.', '该死，坦克拉了周围所有的怪！', '', '¡Me cago en todo! El tanque atrajo a todos los mobs...', '', 'Черт. Танку агрировал всех мобов вокруг.'),
	(1606, 'aoe', 'We gonna die. We gonna die. We gonna die.', 0, 0, '', 'On va mourir. On va mourir. On va mourir.', 'Wir sterben. Wir sterben. Wir sterben.', '我们要死了！我们要死了！我们要死了！', '', 'Vamos a morir. Vamos a morir. Vamos a morir.', '', 'Мы умрем. Мы умрем. Мы умрем.'),
	(1607, 'aoe', 'Whoa! So many toys to play with', 0, 0, '', 'Oh là là ! Tellement de jouets avec lesquels jouer !', 'Whoa! So viel Spielzeug zum Austoben.', '哇！这么多小怪可以玩！', '', '¡Vaya! Tantos juguetes con los que jugar', '', 'Ух ты! Так много игрушек, с которыми можно играть.'),
	(1608, 'aoe', 'I gonna kill them all!', 0, 0, '', 'Je vais les tuer tous !', 'Ich kill sie alle!', '我要干掉他们所有人！', '', '¡Voy a matarlos a todos!', '', 'Я убью их всех!'),
	(1609, 'aoe', 'If the tank dies we are history', 0, 0, '', 'Si le tank meurt, c’est la fin pour nous.', 'Wenn der Tank stirbt, sind wir Geschichte.', '如果坦克挂了，我们就完蛋了！', '', 'Si el tanque muere somos historia', '', 'Если танк умрет, мы в истории.'),
	(1610, 'aoe', 'Aaaaaargh!', 0, 0, '', 'Aaaaaaah!', 'Aaaaaargh!', '啊啊啊啊！', '', '¡Aaaaaargh!', '', 'Аааааргх!'),
	(1611, 'aoe', 'LEEEEERROOOYYYYYYYYYYYY JENNKINNNSSSSSS!!!!!!!', 0, 0, '', 'LEEROOOOOOOYYYYYYYYYYY JENNKINNNSSSSSSS!!!!!!!', 'LEEEEERROOOYYYYYYYYYYYY JENNKINNNSSSSSS!!!!!!!', '李洛伊·詹金斯！！！', '', 'LEEEEERROOOYYYYYYYYYYYY JENNKINNNSSSSSS!!!!!!!', '', 'ЛЕЕЕЕЕЕЕЕЕЕЕЕЕЕЕЕЕЕЕЕЙ ДЖЕНКИНС!!!!!!!'),
	(1612, 'aoe', 'Right. What do we have in AOE?', 0, 0, '', 'Alors, qu’est-ce qu’on a dans AOE?', 'Okay. Was haben wir an AoE?', '好吧，我们有什么群攻技能？', '', 'Claro. ¿Qué tenemos en AOE?', '', 'Правильно. Что у нас есть в AOE?'),
	(1613, 'aoe', 'This gets interesting', 0, 0, '', 'Cela devient intéressant', 'Jetzt wirds interessant.', '这下有意思了！', '', 'Esto se pone interesante', '', 'Это становится интересным.'),
	(1614, 'aoe', 'Cool. Get them in one place for a good flamestrike', 0, 0, '', 'Cool. Rassemble-les au même endroit pour un bon Coup de Flamme.', 'Cool. Zieht sie zusammen für nen schönen Flammenstoß.', '酷！把他们聚一起，给我来个烈焰冲击！', '', 'Genial! Ponlos todos juntos para un buen ataque en area', '', 'Круто. Соберите их в одном месте для хорошего огненного удара.'),
	(1615, 'aoe', 'Kill! Kill! Kill!', 0, 0, '', 'TUER! TUER! TUER!.', 'Kill! Kill! Kill!', '杀！杀！杀！', '', '¡Matar! ¡Matar! ¡Matar!', '', 'Убей! Убей! Убей!'),
	(1616, 'aoe', 'I think my pants are wet', 0, 0, '', 'Je crois que mon pantalon est mouillé.', 'Ich glaub, meine Hose ist nass.', '我感觉我的裤子湿了……', '', 'Creo que mis pantalones están mojados', '', 'Я думаю, что мои штаны мокрые.'),
	(1617, 'aoe', 'We are history', 0, 0, '', 'Nous sommes l’histoire.', 'Wir sind Geschichte.', '我们完蛋了！', '', 'Somos historia', '', 'Мы в истории.'),
	(1618, 'aoe', 'I hope healers are ready. Leeeeroy!', 0, 0, '', 'J’espère que les heal sont prêt. Leeeeroy!', 'Hoffentlich sind die Heiler ready. Leeeeroy!', '希望治疗准备好了，李洛伊！', '', 'Espero que los sanadores estén listos. ¡Leeeroy!', '', 'Надеюсь, целители готовы. Лееерой!'),
	(1619, 'aoe', 'I hope they won’t come for me', 0, 0, '', 'J’espère qu’ils ne viendront pas me chercher.', 'Hoffentlich kommen die nicht zu mir.', '希望他们别冲着我来！', '', 'Espero que no vengan por mí', '', ''),
	(1620, 'aoe', 'Oh no. I can’t see at this slaugther', 0, 0, '', 'Oh non. Je ne peux pas regarder ce massacre.', 'Oh nein. Ich kann bei dem Gemetzel nicht hinsehen.', '哦不，我看不下这场屠杀！', '', 'Oh, no. No puedo ver esta matanza', '', ''),
	(1621, 'loot', 'I hope there will be some money', 0, 0, '', 'J’espère qu’il y aura de l’argent.', 'Hoffentlich gibts Gold.', '希望能有点金币！', '', 'Espero que haya algo de dinero...', '', 'Надеюсь, там будет немного денег.'),
	(1622, 'loot', 'Loot! Loot!', 0, 0, '', 'Butin! Butin!', 'Loot! Loot!', '战利品！战利品！', '', '¡Botín! ¡Botín!', '', 'Лут! Лут!'),
	(1623, 'loot', 'My precious', 0, 0, '', 'Mon précieux', 'Mein Schatz.', '我的宝贝！', '', 'Mi tesoro...', '', 'Мое драгоценное.'),
	(1624, 'loot', 'I hope there is a shiny epic item waiting for me there', 0, 0, '', 'j’espère qu’il y a un objet épique brillant qui m’attend ici', 'Hoffentlich wartet da ein schickes episches Item auf mich.', '希望那儿有件闪闪发光的史诗装备等着我！', '', 'Espero que haya un objeto épico brillante esperándome allí', '', 'Надеюсь, там ждет меня блестящий эпический предмет.'),
	(1625, 'loot', 'I have deep pockets and bags', 0, 0, '', 'J’ai de grandes poches et des sacs profonds.', 'Ich hab tiefe Taschen und Beutel.', '我的口袋和背包都很大！', '', 'Tengo bolsillos profundos y infinitos', '', 'У меня глубокие карманы и сумки.'),
	(1626, 'loot', 'All is mine!', 0, 0, '', 'Tout m’appartient!', 'Alles meins!', '全是我的！', '', '¡Todo es mío!', '', 'Все мое!'),
	(1627, 'loot', 'Hope no gray shit today', 0, 0, '', 'J’espère qu’il n’y aura pas de merde grise aujourd’hui.', 'Hoffentlich heute kein grauer Müll.', '希望今天别出垃圾灰装！', '', 'Espero que hoy no haya mierda gris', '', 'Надеюсь, сегодня не будет серой ерунды.'),
	(1628, 'loot', 'This loot is MINE!', 0, 0, '', 'Ce butin est MIEN !', 'Dieser Loot ist MEINER!', '这战利品是我的！', '', '¡Este botín es MÍO!', '', 'Этот лут - МОЙ!'),
	(1629, 'loot', 'Looting is disgusting but I need money', 0, 0, '', 'Le pillage est répugnant mais j’ai besoin d’argent', 'Looten ist eklig, aber ich brauch Gold.', '摸尸体真恶心，但我需要金币！', '', 'El saqueo es repugnante pero necesito dinero...', '', 'Лутать отвратительно, но мне нужны деньги.'),
	(1630, 'loot', 'Gold!', 0, 0, '', 'ARGENT !', 'Gold!', '金币！', '', '¡Oro!', '', 'Золото!'),
	(1631, 'loot', 'OK. Let’s see what they’ve got', 0, 0, '', 'D’accord. Voyons ce qu’ils ont.', 'Okay. Mal sehen, was sie droppen.', '好吧，看看他们身上有啥！', '', 'OK. Veamos qué tienen', '', ''),
	(1632, 'loot', 'Do not worry. I will loot eveything', 0, 0, '', 'Ne t’inquiète pas. je vais tout piller', 'Keine Sorge. Ich loote alles.', '别担心，我会把所有东西都搜刮干净！', '', 'No te preocupes. Saquearé todo', '', 'Не волнуйтесь. Я все залутаю.'),
	(1633, 'loot', 'I am loot ninja', 0, 0, '', 'Je suis un ninja du butin', 'Ich bin ein Ninja-Looter.', '我是战利品忍者！', '', 'Soy un ladron de tesoros', '', 'Я ниндзя лута.'),
	(1634, 'loot', 'Do I neeed to roll?', 0, 0, '', 'Est-ce que je dois lancer les dés?', 'Muss ich würfeln?', '我需要roll点吗？', '', '¿Necesito lanzar dados?', '', 'Мне нужно бросить кубик?'),
	(1635, 'loot', 'Somebody explain me, where they did put all this stuff?', 0, 0, '', 'Quelqu’un m’explique, où ils ont mis tout ça?', 'Kann mir mal wer erklären, wo die das ganze Zeug versteckt haben?', '谁能告诉我，他们把这些东西都藏哪儿了？', '', 'Alguien me explica, ¿dónde pusieron todas estas cosas?', '', 'Кто-нибудь объясните мне, куда они положили все эти вещи?'),
	(1636, 'loot', 'No, I won’t loot gray shit', 0, 0, '', 'No way, je ne vais pas voler de la merde grise.', 'Nein, ich loote keinen grauen Müll.', '不行，我才不捡这些破烂灰色装备！', '', 'No, no saquearé mierda gris', '', ''),
	(1637, 'loot', 'I’m first. I’m first. I’m first.', 0, 0, '', 'Je suis le premier. Je suis le premier. Je suis le premier.', 'Ich bin zuerst. Ich bin zuerst. Ich bin zuerst.', '我先来！我先来！我先来！', '', '¡Es mio! ¡Es mio! ¡Es mio!', '', ''),
	(1638, 'loot', 'Give me your money!', 0, 0, '', 'Désolé, je ne peux pas faire ça.', 'Gebt mir euer Gold!', '把你的金币都交出来！', '', '¡Dame todo tu dinero!', '', 'Отдай мне свои деньги!'),
	(1639, 'loot', 'My pockets are empty, I need to fill them', 0, 0, '', 'Mes poches sont vides, il faut que je les remplisse.', 'Meine Taschen sind leer, müssen aber voll werden.', '我的口袋空空如也，得赶紧装点东西！', '', 'Mis bolsillos están vacíos y necesitan llenarse!', '', 'Мои карманы пусты, мне нужно их заполнить.'),
	(1640, 'loot', 'I’ve got a new bag for this', 0, 0, '', 'J’ai un nouveau sac pour cela.', 'Hab dafür ne neue Tasche.', '我刚弄了个新背包，正好装这些！', '', 'Tengo una nueva bolsa para esto', '', ''),
	(1641, 'loot', 'I hope I won’t aggro anybody while looting', 0, 0, '', 'J’espère ne pas aggro, je vais loot !', 'Hoffentlich zieh ich beim Looten keine Aggro.', '希望我捡东西的时候别引到什么怪物！', '', 'Espero no ofender a nadie mientras saqueo', '', ''),
	(1642, 'loot', 'Please don’t watch. I am looting', 0, 0, '', 'S’il vous plaît, ne regardez pas. je loot', 'Ich kann nicht looten wenn jemand zusieht.', '别盯着看，我在捡装备呢！', '', 'Por favor, no mires. Estoy saqueando', '', ''),
	(1643, 'loot', 'Ha! You won’t get any piece of it!', 0, 0, '', 'Ha! Tu ne verras rien de cela !', 'Ha! Ihr kriegt davon keinen Krümel!', '哈！你别想分到半点东西！', '', '¡Ja! ¡No obtendrás nada de eso!', '', ''),
	(1644, 'loot', 'Looting is cool', 0, 0, '', 'Le pillage c’est cool', 'Looten ist cool.', '捡战利品真是爽！', '', 'Saquear es genial', '', 'Лутать круто.'),
	(1645, 'loot', 'I like new gear', 0, 0, '', 'J’aime les nouveaux équipements.', 'Ich mag neues Gear.', '我超喜欢新装备！', '', 'Me gusta el equipo nuevo', '', 'Мне нравится новая экипировка.'),
	(1646, 'loot', 'I’l quit if there is nothing valuable again', 0, 0, '', 'j’arrêterai s’il n’y a plus rien de précieux', 'Ich höre auf, wenn schon wieder nichts Wertvolles droppt.', '要是再没什么值钱的东西，我就走人了！', '', 'Me doy por vencido si no hay nada util', '', ''),
	(1647, 'loot', 'I hope it is be a pretty ring', 0, 0, '', 'j’espère que c’est une jolie bague', 'Hoffentlich ist es ein hübscher Ring.', '希望这次能捡到个漂亮的戒指！', '', 'Espero que sea un anillo bonito', '', 'Надеюсь, это будет красивое кольцо.'),
	(1648, 'loot', 'I’l rip the loot from you', 0, 0, '', 'Je t’arracherai le butin', 'Ich reiß dir den Loot aus den Händen.', '我要把战利品从你手里抢过来！', '', 'Te arrancaré el botín', '', ''),
	(1649, 'loot', 'Everybody stay off. I’m going to loot', 0, 0, '', 'Tout le monde, restez loin. Je vais piller.', 'Alle weg da. Ich loote jetzt.', '都别靠近，我要开始捡东西了！', '', '¡Alejaos todos! Voy a lootear', '', ''),
	(1650, 'loot', 'Sweet loot', 0, 0, '', 'Je me suis procuré un butin incroyable !', 'Geiler Loot.', '真是甜美的战利品！', '', 'Dulce botín', '', 'Сладкий лут.'),
	(1651, 'loot', 'The Roll God! Give me an epic today', 0, 0, '', 'Le Dieu des Lancés! Fais-moi vivre une épopée aujourd’hui', 'Oh ihr RNG-Götter! Gewährt mir heute einen Epic beim würfeln.', '掷骰之神！今天赐我一件史诗装备吧！', '', '¡El Dios de los dados! Dame un epico hoy', '', 'Бог Ролла! Дай мне эпик сегодня.'),
	(1652, 'loot', 'Please give me new toys', 0, 0, '', 'S’il te plaît, donne-moi de nouveaux jouets', 'Bitte gib mir neues Spielzeug.', '求你了，给我点新玩意儿吧！', '', 'Por favor, dame nuevos juguetes', '', 'Пожалуйста, дай мне новые игрушки.'),
	(1653, 'loot', 'I hope they carry tasties', 0, 0, '', 'J’espère qu’ils auront des délices.', 'Hoffe, die haben was Leckeres dabei.', '希望他们身上带了点好吃的！', '', 'Espero que caiga algo sabrosos', '', 'Надеюсь, они принесут вкусняшки.'),
	(1654, 'loot', 'The gold is mine. I’ll leave everyting, I promise', 0, 0, '', 'L’or m’appartient. Je laisserai tout, je te le promets.', 'Das Gold gehört mir. Ich lasse euch den Rest, versprochen.', '金币是我的，其他都留给你们，我保证！', '', 'El oro es mío. Dejaré todo lo demas, lo prometo!', '', ''),
	(1655, 'loot', 'No, I can’t resist', 0, 0, '', 'Non, je ne peux pas résister.', 'Nein, ich kann nicht widerstehen.', '不，我忍不住了！', '', 'No, no puedo resistir', '', ''),
	(1656, 'loot', 'I want more!', 0, 0, '', 'Oh, vous en voulez plus!', 'Ich will mehr!', '我还想要更多！', '', '¡Quiero más!', '', 'Я хочу больше!'),
	(1657, 'wait_travel_close', 'I am close, wait for me!', 0, 0, '', 'Je suis presque là, attends-moi !', 'Bin gleich da, wartet auf mich!', '我就在附近，等我一下！', '', '¡Estoy cerca, espérame!', '', 'Я близко, подожди меня!'),
	(1658, 'wait_travel_close', 'I’m not far, please wait!', 0, 0, '', 'Je ne suis pas loin, s’il vous plaît patientez !', 'Bin nicht mehr weit, bitte wartet!', '我不远了，请稍等我！', '', 'No estoy lejos, ¡esperame por favor!', '', 'Я недалеко, погодите!'),
	(1659, 'wait_travel_medium', 'I’m heading to your location', 0, 0, '', 'Je me dirige vers votre emplacement.', 'Bin auf dem Weg zu euch.', '我正朝你的位置赶去！', '', 'Me dirijo a tu ubicación', '', 'Двигаюсь к тебе'),
	(1660, 'wait_travel_medium', 'I’m coming to you', 0, 0, '', 'Je viens vers vous.', 'Ich komme zu euch.', '我正向你靠近！', '', 'Voy hacia ti', '', 'Иду к тебе'),
	(1661, 'wait_travel_far', 'I’m traveling to your location', 0, 0, '', 'Je voyage vers votre destination.', 'Ich reise zu euch.', '我正在前往你的位置！', '', 'Voy a viajar a tu ubicación', '', 'Направляюсь к тебе'),
	(1662, 'wait_travel_far', 'I’m trying to get to you', 0, 0, '', 'Je suis en train de l’atteindre', 'Ich versuche zu euch zu kommen.', '我正努力赶到你那儿！', '', 'Estoy tratando de llegar a ti', '', 'Пытаюсь до тебя добраться'),
	(1663, 'equip_command', 'Equipping %item', 0, 0, '', 'Équipement %item.', 'Rüste %item aus', '装备上 %item', '', 'Me he equipado %item', '', 'Экипирую %item.'),
	(1664, 'unequip_command', '%item unequipped', 0, 0, '', '%item Déséquipé', '%item abgelegt.', '卸下了 %item', '', 'Me he quitado %item', '', '%item снят.'),
	(1665, 'auto_learn_spell', 'I have learned the spells: %spells', 0, 0, '', 'Je viens d’apprendre: %spells', 'Ich habe die Zauber gelernt: %spells', '我学会了这些法术：%spells', '', 'He aprendido los hechizos: %spells', '', 'Я выучил заклинания: %spells.'),
	(1666, 'use_command_item_cooldown', '%item is in cooldown', 0, 0, '', 'L’objet %item est en temps de recharge.', '%item hat Abklingzeit.', '%item 还在冷却中', '', '%item esta recargandose', '', '%item в перезарядке.'),
	(1667, 'use_command_item_not_owned', 'I don’t have %item in my inventory', 0, 0, '', 'Je n’ai pas %item dans mon inventaire.', 'Ich habe %item nicht im Inventar.', '我的背包里没有 %item', '', 'No tengo %item en mi inventario', '', ''),
	(1668, 'use_command_invalid_item', 'The item with the id %item does not exist', 0, 0, '', 'L’article avec l’identifiant %item n’existe pas.', 'Das Item mit der ID %item existiert nicht.', 'ID 为 %item 的物品不存在', '', 'El objeto con el id %item no existe', '', 'Предмет с ID %item не существует.'),
	(1669, 'use_command_socket', 'Socketing %gem into %item', 0, 0, '', 'J’encastre le %gem dans %item.', 'Setze %gem in %item ein.', '将 %gem 镶嵌到 %item 上', '', 'Insertando %gem en %item', '', 'Вставляю %gem в %item.'),
	(1670, 'use_command_item_error', 'I can’t use %item', 0, 0, '', 'Je ne peux pas utiliser %item.', 'Ich kann %item nicht benutzen.', '我无法使用 %item', '', 'No puedo usar %item', '', ''),
	(1671, 'following', 'Following', 0, 0, '', 'Je suis', 'Folge.', '跟随中', '', 'Te sigo', '', 'Следую.'),
	(1672, 'staying', 'Staying', 0, 0, '', 'Je reste ici', 'Bleibe hier.', '待命中', '', 'Me quedo aqui', '', 'Остаюсь.'),
	(1673, 'fleeing', 'Fleeing', 0, 0, '', 'Je m’enfui', 'Fliehe.', '逃跑中', '', 'Huyendo', '', 'Убегаю.'),
	(1674, 'fleeing_far', 'I won’t flee with you, you are too far away', 0, 0, '', 'Je ne vais pas partir avec toi, tu es trop loin.', 'Ich fliehe nicht mit dir, du bist zu weit weg.', '我不会跟你一起逃，你离我太远了！', '', 'No huiré contigo, estás demasiado lejos', '', 'Я с тобой не побегу, ты слишком далеко'),
	(1675, 'grinding', 'Grinding', 0, 0, '', 'Grinding', 'Grinde.', '刷怪中', '', 'Farmeando', '', 'Фармлю.'),
	(1676, 'attacking', 'Attacking', 0, 0, '', 'Attaque en cours !', 'Greife an.', '攻击中', '', 'Atacando', '', 'Атакую.'),
	(1677, 'error_far', 'It is too far away', 0, 0, '', 'C’est trop loin.', 'Das ist zu weit weg.', '距离太远了', '', 'Estas demasiado lejos', '', 'Это слишком далеко.'),
	(1678, 'error_water', 'It is under water', 0, 0, '', 'Cela se trouve sous l’eau', 'Das ist unter Wasser.', '目标在水下', '', 'Estas debajo del agua', '', 'Это под водой.'),
	(1679, 'error_cant_go', 'I can’t go there', 0, 0, '', 'Je ne peux pas y aller.', 'Da kann ich nicht hin.', '我去不了那里', '', 'No puedo ir allí', '', 'Я не могу туда пройти'),
	(1680, 'error_guild', 'I’m not in your guild!', 0, 0, '', 'Je ne fais pas partie de votre guilde!', 'Ich bin nicht in deiner Gilde!', '我不在你的公会里！', '', '¡No estoy en tu hermandad!', '', 'Я не в твоей гильдии'),
	(1681, 'error_gbank_found', 'Can not find a guild bank nearby', 0, 0, '', 'Je ne trouve pas de banque de guilde à proximité.', 'Keine Gildenbank in der Nähe gefunden.', '附近找不到公会银行', '', 'No se puede encontrar un banco de hermandad cercano', '', 'Не могу найти гильдейский банк поблизости.'),
	(1682, 'error_cant_put', 'I can’t put ', 0, 0, '', 'Je ne peux pas déposer ', 'Ich kann nicht ', '我无法存放', '', 'No puedo depositar ', '', 'Я не могу положить'),
	(1683, 'error_gbank_rights', 'I have no rights to put items in the first guild bank tab', 0, 0, '', 'Je n’ai pas le droit de mettre des objets dans le premier onglet de la banque de guilde.', 'Ich habe keine Rechte, Items in den ersten Gildenbank-Reiter zu legen.', '我没有权限将物品放入公会银行的第一个标签页', '', 'No tengo derechos para depositar objetos en la primera pestaña del banco de hermandad', '', 'У меня нет прав на размещение предметов в первой вкладке гильдейского банка.'),
	(1684, 'gbank_put', ' put to guild bank', 0, 0, '', ' déposé dans la banque de guilde.', ' in die Gildenbank gelegt', '已存入公会银行', '', ' depositado en el banco de hermandad', '', ' положено в гильдейский банк.'),
