	(1708, 'rp_missing_reagent_greater_blessing', 'By the Light... I forgot my Symbols of Kings. We’ll make do with %base_spell!', 0, 0, '', 'Par la Lumière... J\'ai oublié mes Symboles du roi. On se contentera de %base_spell !', 'Beim Licht… Ich hab meine Königssymbole vergessen. Na gut, dann nehmen wir eben %base_spell!', '', '', '', '', ''),
	(1709, 'rp_missing_reagent_gift_of_the_wild', 'Nature is generous, my bags are not... out of herbs for %group_spell. Take %base_spell for now!', 0, 0, '', 'La nature est généreuse, pas mes sacs... plus d\'herbes pour %group_spell. Prenez %base_spell pour l\'instant !', 'Die Natur ist großzügig, meine Taschen nicht... keine Kräuter für %group_spell mehr. Nehmt fürs Erste %base_spell!', '', '', '', '', ''),
	(1710, 'rp_missing_reagent_arcane_brilliance', 'Out of Arcane Powder... %group_spell will have to wait. Casting %base_spell!', 0, 0, '', 'Plus de poudre des arcanes... %group_spell attendra. Je lance %base_spell !', 'Arkanes Pulver alle... %group_spell muss warten. Wirke %base_spell!', '', '', '', '', ''),
	(1711, 'rp_missing_reagent_generic', 'Oops, I’m out of components for %group_spell. We’ll go with %base_spell!', 0, 0, '', 'Oups, je n\'ai plus de composants pour %group_spell. On fera avec %base_spell !', 'Ups, mir fehlen die Komponenten für %group_spell. Wir nehmen %base_spell!', '', '', '', '', ''),
